import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import Icon from './CustomIcons';
import { theme } from '../theme/theme';

/**
 * مكون موحد لعرض Banner تحذيري للأدمن
 * ✅ يظهر في جميع الشاشات للأدمن فقط
 * ✅ يوضح أن التداول وهمي دائماً
 * ✅ تمييز واضح بين الوضع التجريبي والحقيقي
 */
const AdminModeBanner = ({ style, tradingMode = 'demo' }) => {
    const isDemo = tradingMode === 'demo';

    return (
        <View style={[styles.container, style]}>
            <Icon name="warning" size={20} color={isDemo ? '#FFA500' : '#FF4444'} />
            <View style={styles.textContainer}>
                <Text style={[styles.text, { color: isDemo ? '#FFA500' : '#FF4444' }]}>
                    {isDemo
                        ? '🔄 وضع تجريبي (Admin) - جميع الصفقات وهمية وآمنة'
                        : '⚠️ وضع حقيقي (Admin) - التداول حقيقي مع مفاتيح Binance'
                    }
                </Text>
                <Text style={styles.subText}>
                    {isDemo
                        ? '💡 آمن للاختبار - لا توجد مخاطر مالية'
                        : '⚡ تداول حقيقي - جميع الصفقات حقيقية'
                    }
                </Text>
            </View>
        </View>
    );
};

const styles = StyleSheet.create({
    container: {
        flexDirection: 'row',
        alignItems: 'center',
        backgroundColor: 'rgba(255, 165, 0, 0.15)',
        borderLeftWidth: 3,
        borderLeftColor: '#FFA500',
        paddingHorizontal: 16,
        paddingVertical: 12,
        marginHorizontal: 16,
        marginBottom: 12,
        borderRadius: 8,
    },
    textContainer: {
        flex: 1,
        marginStart: 8,
    },
    text: {
        fontSize: 14,
        fontWeight: '600',
        marginBottom: 2,
    },
    subText: {
        fontSize: 12,
        fontWeight: '400',
        opacity: 0.8,
    },
});

export default AdminModeBanner;

/**
 * 📡 Connection Status Bar - شريط حالة الاتصال
 * ✅ يستخدم TradingModeContext المركزي لحالة الاتصال
 */

import React, { useState, useEffect, useRef } from 'react';
import {
    View,
    Text,
    StyleSheet,
    Animated,
} from 'react-native';
import { theme } from '../theme/theme';
import { useTradingModeContext } from '../context/TradingModeContext';

const ConnectionStatusBar = () => {
    // ✅ استخدام حالة الاتصال من Context المركزي
    const { isConnected } = useTradingModeContext();

    const [showBar, setShowBar] = useState(false);
    const [fadeAnim] = useState(new Animated.Value(0));
    const prevConnectedRef = useRef(isConnected);

    // ✅ مراقبة تغيّر حالة الاتصال من Context
    useEffect(() => {
        const prevConnected = prevConnectedRef.current;
        prevConnectedRef.current = isConnected;

        // تغيّرت الحالة
        if (prevConnected !== isConnected) {
            if (!isConnected) {
                // فقد الاتصال - إظهار الشريط
                setShowBar(true);
                Animated.timing(fadeAnim, {
                    toValue: 1,
                    duration: 300,
                    useNativeDriver: true,
                }).start();
            } else {
                // استعادة الاتصال - إخفاء بعد 2 ثانية
                setTimeout(() => {
                    Animated.timing(fadeAnim, {
                        toValue: 0,
                        duration: 300,
                        useNativeDriver: true,
                    }).start(() => setShowBar(false));
                }, 2000);
            }
        }
    }, [isConnected, fadeAnim]);

    if (!showBar) {return null;}

    return (
        <Animated.View
            style={[
                styles.container,
                { opacity: fadeAnim },
                isConnected ? styles.connected : styles.disconnected,
            ]}
        >
            <View style={styles.dot} />
            <Text style={styles.text}>
                {isConnected ? 'تم استعادة الاتصال' : 'لا يوجد اتصال بالخادم'}
            </Text>
        </Animated.View>
    );
};

const styles = StyleSheet.create({
    container: {
        position: 'absolute',
        bottom: 90,
        left: 20,
        right: 20,
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        paddingVertical: 10,
        paddingHorizontal: 16,
        borderRadius: 10,
        zIndex: 999,
    },
    connected: {
        backgroundColor: 'rgba(16, 185, 129, 0.9)',
    },
    disconnected: {
        backgroundColor: 'rgba(239, 68, 68, 0.9)',
    },
    dot: {
        width: 8,
        height: 8,
        borderRadius: 4,
        backgroundColor: '#FFFFFF',
        marginEnd: 8,
    },
    text: {
        fontSize: 14,
        fontWeight: '500',
        color: '#FFFFFF',
    },
});

export default ConnectionStatusBar;

/**
 * نظام رسائل مخصص يتناسق مع Dark Theme
 * بديل احترافي لـ Alert.alert()
 */

import React from 'react';
import {
  View,
  Text,
  Modal,
  TouchableOpacity,
  StyleSheet,
  Animated,
  Dimensions,
  BackHandler,
} from 'react-native';
import { theme as Theme } from '../theme/theme';

const { width } = Dimensions.get('window');

class CustomAlertService {
  constructor() {
    this.alertRef = null;
  }

  setAlertRef(ref) {
    this.alertRef = ref;
  }

  show(title, message, buttons = [], options = {}) {
    if (this.alertRef) {
      this.alertRef.show(title, message, buttons, options);
    }
  }

  success(title, message, onPress) {
    this.show(title, message, [{ text: 'موافق', onPress }], { type: 'success' });
  }

  error(title, message, onPress) {
    this.show(title, message, [{ text: 'موافق', onPress }], { type: 'error' });
  }

  warning(title, message, buttons) {
    this.show(title, message, buttons, { type: 'warning' });
  }

  confirm(title, message, onConfirm, onCancel) {
    this.show(title, message, [
      { text: 'إلغاء', style: 'cancel', onPress: onCancel },
      { text: 'تأكيد', onPress: onConfirm },
    ], { type: 'warning' });
  }
}

export const AlertService = new CustomAlertService();

export default class CustomAlert extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      visible: false,
      title: '',
      message: '',
      buttons: [],
      type: 'default',
    };
    this.fadeAnim = new Animated.Value(0);
    this.scaleAnim = new Animated.Value(0.8);
  }

  componentDidMount() {
    AlertService.setAlertRef(this);
    this.backHandler = BackHandler.addEventListener('hardwareBackPress', this.handleBackPress);
  }

  componentWillUnmount() {
    this.backHandler?.remove();
  }

  handleBackPress = () => {
    if (this.state.visible) {
      this.hide();
      return true;
    }
    return false;
  };

  show = (title, message, buttons = [], options = {}) => {
    const defaultButtons = buttons.length > 0 ? buttons : [{ text: 'موافق', onPress: () => { } }];

    this.setState({
      visible: true,
      title,
      message,
      buttons: defaultButtons,
      type: options.type || 'default',
    }, () => {
      Animated.parallel([
        Animated.timing(this.fadeAnim, {
          toValue: 1,
          duration: 200,
          useNativeDriver: true,
        }),
        Animated.spring(this.scaleAnim, {
          toValue: 1,
          tension: 50,
          friction: 7,
          useNativeDriver: true,
        }),
      ]).start();
    });
  };

  hide = (callback) => {
    Animated.parallel([
      Animated.timing(this.fadeAnim, {
        toValue: 0,
        duration: 150,
        useNativeDriver: true,
      }),
      Animated.timing(this.scaleAnim, {
        toValue: 0.8,
        duration: 150,
        useNativeDriver: true,
      }),
    ]).start(() => {
      this.setState({ visible: false });
      if (callback) {callback();}
    });
  };

  handleButtonPress = (button) => {
    this.hide(() => {
      if (button.onPress) {
        button.onPress();
      }
    });
  };

  getIconAndColor = () => {
    switch (this.state.type) {
      case 'success':
        return { icon: '✓', color: Theme.colors.success };
      case 'error':
        return { icon: '✕', color: Theme.colors.error };
      case 'warning':
        return { icon: '⚠', color: Theme.colors.warning };
      case 'info':
        return { icon: 'ℹ', color: Theme.colors.info };
      default:
        return { icon: null, color: Theme.colors.primary };
    }
  };

  render() {
    const { visible, title, message, buttons } = this.state;
    const { icon, color } = this.getIconAndColor();

    return (
      <Modal
        visible={visible}
        transparent
        animationType="none"
        statusBarTranslucent
        onRequestClose={this.handleBackPress}
      >
        <TouchableOpacity
          activeOpacity={1}
          onPress={() => this.hide()}
          style={styles.overlay}
        >
          <Animated.View
            style={[
              styles.overlayBackground,
              { opacity: this.fadeAnim },
            ]}
          />
        </TouchableOpacity>

        <View style={styles.container} pointerEvents="box-none">
          <Animated.View
            style={[
              styles.alertBox,
              {
                opacity: this.fadeAnim,
                transform: [{ scale: this.scaleAnim }],
              },
            ]}
          >
            {icon && (
              <View style={[styles.iconContainer, { backgroundColor: `${color}15` }]}>
                <Text style={[styles.icon, { color }]}>{icon}</Text>
              </View>
            )}

            <Text style={styles.title}>{title}</Text>

            {message ? (
              <Text style={styles.message}>{message}</Text>
            ) : null}

            <View style={styles.buttonsContainer}>
              {buttons.map((button, index) => {
                const isCancel = button.style === 'cancel';
                const isPrimary = !isCancel && index === buttons.length - 1;

                return (
                  <TouchableOpacity
                    key={index}
                    onPress={() => this.handleButtonPress(button)}
                    style={[
                      styles.button,
                      isPrimary && styles.buttonPrimary,
                      isCancel && styles.buttonCancel,
                      buttons.length === 1 && styles.buttonSingle,
                    ]}
                    activeOpacity={0.8}
                  >
                    <Text
                      style={[
                        styles.buttonText,
                        isPrimary && styles.buttonTextPrimary,
                        isCancel && styles.buttonTextCancel,
                      ]}
                    >
                      {button.text}
                    </Text>
                  </TouchableOpacity>
                );
              })}
            </View>
          </Animated.View>
        </View>
      </Modal>
    );
  }
}

const styles = StyleSheet.create({
  overlay: {
    ...StyleSheet.absoluteFillObject,
    zIndex: 999,
  },
  overlayBackground: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: 'rgba(0, 0, 0, 0.7)',
  },
  container: {
    ...StyleSheet.absoluteFillObject,
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
    paddingHorizontal: 24,
  },
  alertBox: {
    backgroundColor: '#161925',
    borderRadius: 16,
    padding: 24,
    width: '100%',
    maxWidth: 340,
    borderWidth: 1,
    borderColor: 'rgba(255, 255, 255, 0.1)',
    shadowColor: '#000000', shadowOffset: { width: 0, height: 10 }, shadowOpacity: 0.37, shadowRadius: 7.49, elevation: 12,
  },
  iconContainer: {
    width: 56,
    height: 56,
    borderRadius: 28,
    justifyContent: 'center',
    alignItems: 'center',
    alignSelf: 'center',
    marginBottom: 12,
  },
  icon: {
    fontSize: 28,
    fontWeight: '700',
  },
  title: {
    fontSize: 20,
    fontWeight: '700',
    color: '#FFFFFF',
    textAlign: 'center',
    marginBottom: 8,
  },
  message: {
    fontSize: 15,
    color: '#A0A0A0',
    textAlign: 'center',
    lineHeight: 22,
    marginBottom: 16,
  },
  buttonsContainer: {
    flexDirection: 'row',
    gap: 12,
    marginTop: 12,
  },
  button: {
    flex: 1,
    paddingVertical: 12,
    paddingHorizontal: 16,
    borderRadius: 12,
    backgroundColor: '#1E2235',
    borderWidth: 1,
    borderColor: 'rgba(255, 255, 255, 0.1)',
    minHeight: 48,
    justifyContent: 'center',
    alignItems: 'center',
  },
  buttonSingle: {
    flex: 1,
  },
  buttonPrimary: {
    backgroundColor: Theme.colors.primary,
    borderColor: Theme.colors.primary,
  },
  buttonCancel: {
    backgroundColor: 'transparent',
    borderColor: '#2A3250',
  },
  buttonText: {
    fontSize: 16,
    fontWeight: '600',
    color: '#FFFFFF',
  },
  buttonTextPrimary: {
    color: '#FFFFFF',
  },
  buttonTextCancel: {
    color: '#A0A0A0',
  },
});

import React, { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, I18nManager, ActivityIndicator, Modal, Animated } from 'react-native';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import LinearGradient from 'react-native-linear-gradient';
import { theme } from '../theme/theme';
import { useNavigation } from '@react-navigation/native';
import BrandIcon from './BrandIcons';
import UnifiedBrandLogo from './UnifiedBrandLogo';
import { useTradingModeContext } from '../context/TradingModeContext';
import { hapticLight, hapticWarning, hapticSuccess } from '../utils/HapticFeedback';
import { AlertService } from './CustomAlert';
import ToastService from '../services/ToastService';
import { TooltipContent } from './Tooltip';
import Logger from '../services/LoggerService';

// أيقونات مخصصة للـ Header
const ArrowLeftIcon = ({ size = 24, color = '#FFFFFF' }) => <BrandIcon name="arrow-back" size={size} color={color} />;
const ArrowRightIcon = ({ size = 24, color = '#FFFFFF' }) => <BrandIcon name="arrow-forward" size={size} color={color} />;
const NotificationIcon = ({ size = 24, color = '#FFFFFF' }) => <BrandIcon name="notification" size={size} color={color} />;

const isRTL = I18nManager.isRTL;

/**
 * البنر العلوي الموحد (Global Header)
 * ✅ تصميم جديد مستوحى من Stakent
 * ✅ تدرج بنفسجي أنيق
 */
const GlobalHeader = ({
    title,
    showBack = false,
    onBack,
    rightAction,
    showNotification = false,
    onNotificationPress,
    subtitle,
    variant = 'default', // 'default' | 'transparent' | 'gradient'
    showLogo = true,
    isAdminUser = false, // ✅ يمكن تمريره كـ prop
}) => {
    const insets = useSafeAreaInsets();
    const navigation = useNavigation();

    // ✅ وضع التداول للأدمن (يظهر في Header)
    const { isAdmin: contextIsAdmin, getCurrentViewMode, getModeColor, changeTradingMode, isLoading: modeLoading, hasBinanceKeys, tradingMode, userId } = useTradingModeContext();

    // ✅ استخدام isAdminUser من props إذا تم تمريره، وإلا استخدم من Context
    const isAdmin = isAdminUser !== false ? isAdminUser : contextIsAdmin;
    const currentMode = getCurrentViewMode?.() || tradingMode || 'demo';
    const modeColor = getModeColor?.() || '#F59E0B';
    const [switching, setSwitching] = useState(false);
    const [showAutoTooltip, setShowAutoTooltip] = useState(false);
    const scaleAnim = React.useRef(new Animated.Value(0)).current;

    // ✅ فحص: يجب أن يكون المستخدم مسجل دخول لعرض الشارة
    const isUserLoggedIn = userId !== null && userId !== undefined;

    // ✅ تصحيح: تأكد من أن isAdmin محدث
    Logger.debug(`GlobalHeader - isAdmin: ${isAdmin}, mode: ${currentMode}, isLoggedIn: ${isUserLoggedIn}`, 'GlobalHeader');

    // ✅ Tooltip animation
    React.useEffect(() => {
        if (showAutoTooltip) {
            Animated.spring(scaleAnim, {
                toValue: 1,
                tension: 50,
                friction: 7,
                useNativeDriver: true,
            }).start();
        } else {
            Animated.timing(scaleAnim, {
                toValue: 0,
                duration: 150,
                useNativeDriver: true,
            }).start();
        }
    }, [showAutoTooltip]);

    // ✅ دالة تبديل الوضع للأدمن
    const handleToggleMode = async () => {
        console.log(`[GlobalHeader] handleToggleMode: isAdmin=${isAdmin}, switching=${switching}, modeLoading=${modeLoading}, currentMode=${currentMode}`);

        if (!isAdmin || switching || modeLoading) {
            console.log(`[GlobalHeader] Blocked: isAdmin=${isAdmin}, switching=${switching}, modeLoading=${modeLoading}`);
            return;
        }

        const newMode = currentMode === 'demo' ? 'real' : 'demo';
        console.log(`[GlobalHeader] Switching from ${currentMode} to ${newMode}`);

        // تحذير عند التبديل للوضع الحقيقي
        if (newMode === 'real') {
            if (!hasBinanceKeys) {
                hapticWarning();
                ToastService.showWarning('يجب إضافة مفاتيح Binance أولاً');
                return;
            }

            AlertService.confirm(
                '⚠️ تحذير هام',
                'أنت على وشك التبديل للتداول الحقيقي.\n\nجميع الصفقات ستكون حقيقية وقد تؤدي لخسائر مالية.',
                async () => {
                    await executeToggle(newMode);
                },
                () => { },
                'تأكيد التبديل',
                'إلغاء'
            );
        } else {
            await executeToggle(newMode);
        }
    };

    const executeToggle = async (newMode) => {
        console.log(`[GlobalHeader] executeToggle called with newMode=${newMode}`);
        setSwitching(true);
        hapticLight();
        try {
            console.log(`[GlobalHeader] Calling changeTradingMode(${newMode})...`);
            const result = await changeTradingMode(newMode);
            console.log('[GlobalHeader] changeTradingMode result:', JSON.stringify(result));

            if (result?.success) {
                console.log('[GlobalHeader] Toggle successful!');
                hapticSuccess();
                ToastService.showSuccess(`تم التبديل إلى الوضع ${newMode === 'demo' ? 'التجريبي' : 'الحقيقي'}`);
            } else {
                hapticWarning();
                ToastService.showError(result?.error || 'فشل التبديل');
            }
        } catch (error) {
            hapticWarning();

            let errorMessage = 'فشل التبديل بين الأوضاع';
            if (error?.response?.data?.error) {
                errorMessage = error.response.data.error;
            } else if (error?.code === 'ECONNABORTED' || error?.message?.includes('timeout')) {
                errorMessage = 'انتهى وقت الانتظار. يرجى المحاولة مرة أخرى';
            } else if (error?.code === 'ERR_NETWORK' || error?.message?.includes('Network Error')) {
                errorMessage = 'فشل الاتصال بالخادم. تحقق من اتصالك بالإنترنت';
            }

            ToastService.showError(errorMessage);
        } finally {
            setSwitching(false);
        }
    };

    return (
        <View style={[styles.container, { paddingTop: insets.top }]}>
            {/* خط التدرج العلوي */}
            <LinearGradient
                colors={theme.colors.gradientPrimary}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 0 }}
                style={styles.gradientLine}
            />

            <View style={styles.content}>
                {/* زر الرجوع أو الشعار - RTL: يظهر على اليمين */}
                <View style={isRTL ? styles.rightContainer : styles.leftContainer}>
                    {showBack ? (
                        <TouchableOpacity
                            onPress={() => { hapticLight(); onBack ? onBack() : navigation.goBack(); }}
                            style={styles.backButton}
                            activeOpacity={0.7}
                        >
                            {/* في RTL: السهم يشير لليمين للرجوع */}
                            {isRTL ? (
                                <ArrowRightIcon size={24} color={theme.colors.text} />
                            ) : (
                                <ArrowLeftIcon size={24} color={theme.colors.text} />
                            )}
                        </TouchableOpacity>
                    ) : showLogo ? (
                        <UnifiedBrandLogo variant="header" size={36} />
                    ) : <View style={{ width: 40 }} />}
                </View>

                {/* العنوان + وضع التداول للأدمن + شارة AUTO */}
                <View style={styles.centerContainer}>
                    <View style={styles.titleRow}>
                        <Text style={styles.title} numberOfLines={1}>
                            {title || '1B Trading'}
                        </Text>

                        {/* ✅ شارة وضع التداول للأدمن - فقط بعد تسجيل الدخول */}
                        {isAdmin && isUserLoggedIn && userId && (
                            <TouchableOpacity
                                onPress={handleToggleMode}
                                disabled={switching || modeLoading}
                                activeOpacity={0.7}
                                style={[styles.modeBadgeLarge, {
                                    backgroundColor: currentMode === 'demo' ? '#F59E0B' : '#10B981',
                                    borderColor: currentMode === 'demo' ? '#F59E0B' : '#10B981',
                                }]}
                            >
                                {switching ? (
                                    <ActivityIndicator size="small" color="#FFFFFF" />
                                ) : (
                                    <View style={styles.modeBadgeContent}>
                                        <Text style={styles.modeBadgeTextLarge}>
                                            {currentMode === 'demo' ? '🔴 تجريبي' : '🟢 حقيقي'}
                                        </Text>
                                        <BrandIcon name="swap" size={14} color="#FFFFFF" />
                                    </View>
                                )}
                            </TouchableOpacity>
                        )}
                    </View>
                    {subtitle && (
                        <Text style={styles.subtitle} numberOfLines={1}>
                            {subtitle}
                        </Text>
                    )}
                </View>

                {/* الإجراء الأيمن - RTL: يظهر على اليسار */}
                <View style={isRTL ? styles.leftContainer : styles.rightContainer}>
                    {rightAction ? rightAction : showNotification ? (
                        <TouchableOpacity
                            onPress={() => { hapticLight(); onNotificationPress && onNotificationPress(); }}
                            style={styles.iconButton}
                            activeOpacity={0.7}
                        >
                            <NotificationIcon size={24} color={theme.colors.textSecondary} />
                        </TouchableOpacity>
                    ) : null}
                </View>
            </View>

            {/* خط فاصل سفلي */}
            <View style={styles.bottomBorder} />

            {/* ✅ Tooltip للنظام الآلي */}
            <Modal
                visible={showAutoTooltip}
                transparent
                animationType="none"
                onRequestClose={() => setShowAutoTooltip(false)}
            >
                <TouchableOpacity
                    style={styles.tooltipOverlay}
                    activeOpacity={1}
                    onPress={() => setShowAutoTooltip(false)}
                >
                    <Animated.View
                        style={[
                            styles.tooltipBox,
                            {
                                transform: [{ scale: scaleAnim }],
                            },
                        ]}
                    >
                        <Text style={styles.tooltipTitle}>🤖 نظام تداول آلي 100%</Text>
                        <Text style={styles.tooltipDescription}>
                            النظام يتداول تلقائياً كل 60 ثانية - أنت فقط تراقب النتائج
                        </Text>

                        <View style={styles.tooltipSection}>
                            <Text style={styles.tooltipSectionLabel}>✅ أنت تفعل:</Text>
                            <Text style={styles.tooltipItem}>• تسجيل الدخول</Text>
                            <Text style={styles.tooltipItem}>• ربط مفاتيح Binance</Text>
                            <Text style={styles.tooltipItem}>• مراقبة النتائج</Text>
                        </View>

                        <View style={styles.tooltipSection}>
                            <Text style={styles.tooltipSectionLabel}>🤖 النظام يفعل (تلقائياً):</Text>
                            <Text style={styles.tooltipItem}>• اختيار العملات كل 12 ساعة</Text>
                            <Text style={styles.tooltipItem}>• فتح صفقات كل 60 ثانية</Text>
                            <Text style={styles.tooltipItem}>• إغلاق الصفقات تلقائياً</Text>
                            <Text style={styles.tooltipItem}>• تحديث المحفظة</Text>
                        </View>

                        <View style={styles.tooltipNote}>
                            <Text style={styles.tooltipNoteText}>
