/**
 * PasswordPromptModal - Modal لإدخال كلمة المرور
 * بديل لـ Alert.prompt الذي لا يعمل على Android
 */

import React, { useState, useRef, useEffect } from 'react';
import {
    View,
    Text,
    TouchableOpacity,
    StyleSheet,
    Modal,
    KeyboardAvoidingView,
    Platform,
} from 'react-native';
import { theme } from '../theme/theme';
import ModernInput from './ModernInput';

const PasswordPromptModal = ({
    visible,
    title = '🔐 تأكيد الهوية',
    message = 'أدخل كلمة المرور للتأكيد:',
    placeholder = 'كلمة المرور',
    confirmText = 'تأكيد',
    cancelText = 'إلغاء',
    onConfirm,
    onCancel,
    confirmButtonStyle = 'destructive', // 'default' | 'destructive'
}) => {
    const [password, setPassword] = useState('');

    // reset password when visibility changes
    useEffect(() => {
        if (!visible) {
            setPassword('');
        }
    }, [visible]);

    const handleConfirm = () => {
        if (password.trim()) {
            onConfirm(password);
            setPassword(''); // إعادة تعيين
        }
    };

    const handleCancel = () => {
        setPassword(''); // إعادة تعيين
        onCancel();
    };

    return (
        <Modal
            visible={visible}
            transparent
            animationType="fade"
            onRequestClose={handleCancel}
        >
            <KeyboardAvoidingView
                style={styles.overlay}
                behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
            >
                <TouchableOpacity
                    style={styles.backdrop}
                    activeOpacity={1}
                    onPress={handleCancel}
                />

                <View style={styles.modalContent}>
                    {/* Header */}
                    <View style={styles.header}>
                        <Text style={styles.title}>{title}</Text>
                        {message ? (
                            <Text style={styles.message}>{message}</Text>
                        ) : null}
                    </View>

                    {/* Input */}
                    <ModernInput
                        value={password}
                        onChangeText={setPassword}
                        placeholder={placeholder}
                        secureTextEntry={true}
                        autoFocus={true}
                        autoCapitalize="none"
                        returnKeyType="done"
                        onSubmitEditing={handleConfirm}
                        icon="lock"
                        containerStyle={{ marginBottom: 20 }}
                    />

                    {/* Buttons */}
                    <View style={styles.buttons}>
                        <TouchableOpacity
                            style={[styles.button, styles.cancelButton]}
                            onPress={handleCancel}
                            activeOpacity={0.7}
                        >
                            <Text style={styles.cancelButtonText}>
                                {cancelText}
                            </Text>
                        </TouchableOpacity>

                        <TouchableOpacity
                            style={[
                                styles.button,
                                confirmButtonStyle === 'destructive'
                                    ? styles.destructiveButton
                                    : styles.confirmButton,
                            ]}
                            onPress={handleConfirm}
                            activeOpacity={0.7}
                            disabled={!password.trim()}
                        >
                            <Text
                                style={[
                                    confirmButtonStyle === 'destructive'
                                        ? styles.destructiveButtonText
                                        : styles.confirmButtonText,
                                    !password.trim() && styles.disabledButtonText,
                                ]}
                            >
                                {confirmText}
                            </Text>
                        </TouchableOpacity>
                    </View>
                </View>
            </KeyboardAvoidingView>
        </Modal>
    );
};

