/**
 * Portfolio Context - إدارة بيانات المحفظة المركزية
 * ✅ يمنع تكرار استدعاءات API
 * ✅ Cache ذكي مع TTL
 * ✅ تحديث تلقائي كل 30 ثانية
 * ✅ مشاركة البيانات بين جميع الشاشات
 */

import React, { createContext, useContext, useState, useCallback, useEffect, useRef } from 'react';
import DatabaseApiService from '../services/DatabaseApiService';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useTradingModeContext } from './TradingModeContext';

const PortfolioContext = createContext();

// Cache TTL بالمللي ثانية (30 ثانية)
const CACHE_TTL = 30000;

export const PortfolioProvider = ({ children }) => {
    // بيانات المستخدم
    const [userId, setUserId] = useState(null);
    const [isAdmin, setIsAdmin] = useState(false);

    // بيانات المحفظة - ✅ بدون بيانات افتراضية
    const [portfolio, setPortfolio] = useState(null);
    const [demoPortfolio, setDemoPortfolio] = useState(null);
    const [realPortfolio, setRealPortfolio] = useState(null);

    // حالة التحميل
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);

    // Cache timestamps
    const lastFetchRef = useRef({
        portfolio: 0,
        demo: 0,
        real: 0,
    });

    // استخدام TradingModeContext للحصول على الوضع الحالي
    const { getCurrentViewMode, refreshCounter } = useTradingModeContext();

    // تحميل بيانات المستخدم - فقط إذا كان token موجود
    const loadUserData = useCallback(async () => {
        try {
            const token = await AsyncStorage.getItem('authToken');
            if (!token) {
                setUserId(null);
                setIsAdmin(false);
                return null;
            }

            const userData = await AsyncStorage.getItem('userData');
            if (userData) {
                let user;
                try {
                    user = JSON.parse(userData);
                } catch (parseError) {
                    console.error('[CRASH_PREVENTION] فشل تحليل بيانات المستخدم في PortfolioContext:', parseError);
                    return null;
                }
                setUserId(user.id);
                // ✅ دعم كلا من user_type و userType للتوافق
                setIsAdmin(user.user_type === 'admin' || user.userType === 'admin');
                return user;
            }
        } catch (error) {
            console.error('[PortfolioContext] Error loading user data:', error);
        }
        return null;
    }, []);

    // فحص صلاحية Cache
    const isCacheValid = useCallback((type) => {
        const now = Date.now();
        return (now - lastFetchRef.current[type]) < CACHE_TTL;
    }, []);

    // جلب المحفظة الرئيسية
    const fetchPortfolio = useCallback(async (forceRefresh = false) => {
        if (!userId) {return null;}

        if (!forceRefresh && isCacheValid('portfolio') && portfolio) {
            return portfolio;
        }

        try {
            setIsLoading(true);
            setError(null);

            // ✅ إضافة fallback آمن - إذا كان getCurrentViewMode undefined، استخدم 'demo'
            let currentMode = 'demo';
            try {
                const mode = getCurrentViewMode?.();
                if (mode) {
                    currentMode = mode;
                }
            } catch (modeError) {
                console.warn('[PortfolioContext] Error getting current mode, using default:', modeError);
                currentMode = 'demo';
            }

            // ✅ التحقق من صحة mode قبل الإرسال - استخدام demo كافتراضي
            if (!currentMode || !['demo', 'real', 'auto'].includes(currentMode)) {
                currentMode = 'demo';
            }

            const response = await DatabaseApiService.getPortfolio(userId, currentMode);

            if (response?.success && response?.data) {
                setPortfolio(response.data);
                lastFetchRef.current.portfolio = Date.now();
                return response.data;
            }
        } catch (err) {
            console.error('[PortfolioContext] Error fetching portfolio:', err);
            setError(err.message);
        } finally {
            setIsLoading(false);
        }
        return null;
    }, [userId, portfolio, isCacheValid, getCurrentViewMode]);

    // جلب محفظة Demo
    const fetchDemoPortfolio = useCallback(async (forceRefresh = false) => {
        if (!userId || !isAdmin) {return null;}

        if (!forceRefresh && isCacheValid('demo') && demoPortfolio) {
            return demoPortfolio;
        }

        try {
            const response = await DatabaseApiService.getPortfolio(userId, 'demo');
            if (response?.success && response?.data) {
                setDemoPortfolio(response.data);
                lastFetchRef.current.demo = Date.now();
                return response.data;
            }
        } catch (err) {
            console.error('[PortfolioContext] Error fetching demo portfolio:', err);
        }
        return null;
    }, [userId, isAdmin, demoPortfolio, isCacheValid]);

    // جلب محفظة Real
    const fetchRealPortfolio = useCallback(async (forceRefresh = false) => {
        if (!userId || !isAdmin) {return null;}

        if (!forceRefresh && isCacheValid('real') && realPortfolio) {
            return realPortfolio;
        }

        try {
            const response = await DatabaseApiService.getPortfolio(userId, 'real');
            if (response?.success && response?.data) {
                setRealPortfolio(response.data);
                lastFetchRef.current.real = Date.now();
                return response.data;
            }
        } catch (err) {
            console.error('[PortfolioContext] Error fetching real portfolio:', err);
        }
        return null;
    }, [userId, isAdmin, realPortfolio, isCacheValid]);

    // جلب جميع المحافظ (للأدمن)
    const fetchAllPortfolios = useCallback(async (forceRefresh = false) => {
        if (!userId) {return;}

        setIsLoading(true);
        try {
            const currentMode = getCurrentViewMode?.() || 'demo';

            // جلب المحفظة الرئيسية
            await fetchPortfolio(forceRefresh);

            // للأدمن: جلب Demo و Real
            if (isAdmin) {
                await Promise.all([
                    fetchDemoPortfolio(forceRefresh),
                    fetchRealPortfolio(forceRefresh),
                ]);
            }
        } finally {
            setIsLoading(false);
        }
    }, [userId, isAdmin, fetchPortfolio, fetchDemoPortfolio, fetchRealPortfolio, getCurrentViewMode]);

    const refreshPortfolios = useCallback(async () => {
        lastFetchRef.current = { portfolio: 0, demo: 0, real: 0 };
        await fetchAllPortfolios(true);
    }, [fetchAllPortfolios]);

    // ✅ FIX: Listen for cache invalidation events from backend
    useEffect(() => {
        const { DeviceEventEmitter } = require('react-native');
        const subscription = DeviceEventEmitter.addListener('CACHE_INVALIDATE', (key) => {
            if (key === 'portfolio' || key === 'stats' || key === 'admin_dashboard') {
                // Force refresh on next fetch
                lastFetchRef.current.portfolio = 0;
                lastFetchRef.current.demo = 0;
                lastFetchRef.current.real = 0;

                // Auto-refresh if user is viewing
                if (userId) {
                    fetchAllPortfolios(true);
                }
            }
        });

        return () => subscription.remove();
    }, [userId, fetchAllPortfolios]);

    // تحميل البيانات عند البداية
    useEffect(() => {
        loadUserData().then(user => {
            if (user) {
                fetchAllPortfolios(true);
            }
        });
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    useEffect(() => {
        if (refreshCounter > 0 && userId) {
            refreshPortfolios();
        }
    }, [refreshCounter, userId]); // eslint-disable-line react-hooks/exhaustive-deps

    // ✅ مرجع للتحديث التلقائي لتجنب infinite loop
    const autoRefreshRef = useRef(null);

    // تحديث تلقائي كل 30 ثانية - فقط إذا كان المستخدم مسجل دخول
    useEffect(() => {
        const startAutoRefresh = async () => {
            // إيقاف أي interval سابق
            if (autoRefreshRef.current) {
                clearInterval(autoRefreshRef.current);
                autoRefreshRef.current = null;
            }

            const token = await AsyncStorage.getItem('authToken');
            if (!userId || !token) {return;}

            autoRefreshRef.current = setInterval(async () => {
                const currentToken = await AsyncStorage.getItem('authToken');
                if (!currentToken) {
                    if (autoRefreshRef.current) {
                        clearInterval(autoRefreshRef.current);
                        autoRefreshRef.current = null;
                    }
                    return;
                }
                // ✅ استدعاء مباشر بدلاً من fetchAllPortfolios لتجنب dependency loop
                lastFetchRef.current = { portfolio: 0, demo: 0, real: 0 };
                if (userId) {
                    await fetchPortfolio(true);
                    if (isAdmin) {
                        await Promise.all([
                            fetchDemoPortfolio(true),
                            fetchRealPortfolio(true),
                        ]);
                    }
                }
            }, CACHE_TTL);
        };

        startAutoRefresh();

        return () => {
            if (autoRefreshRef.current) {
                clearInterval(autoRefreshRef.current);
                autoRefreshRef.current = null;
            }
        };
    }, [userId, isAdmin]); // ✅ فقط userId و isAdmin - بدون fetchAllPortfolios

    // تحديث userId عند تغيير المستخدم
    const updateUser = useCallback(async (newUserId, newIsAdmin = false) => {
        setUserId(newUserId);
        setIsAdmin(newIsAdmin);
        // مسح Cache عند تغيير المستخدم
        lastFetchRef.current = { portfolio: 0, demo: 0, real: 0 };
        setPortfolio(null);
        setDemoPortfolio(null);
        setRealPortfolio(null);
    }, []);

    const value = {
        // البيانات
        portfolio,
        demoPortfolio,
        realPortfolio,
        isLoading,
        error,
        userId,
        isAdmin,

        // الدوال
        fetchPortfolio,
        fetchDemoPortfolio,
        fetchRealPortfolio,
        fetchAllPortfolios,
        refreshPortfolios,
        updateUser,

        // معلومات Cache
        isCacheValid,
        lastFetch: lastFetchRef.current,
    };

    return (
        <PortfolioContext.Provider value={value}>
            {children}
        </PortfolioContext.Provider>
    );
};

// Hook للاستخدام
export const usePortfolioContext = () => {
    const context = useContext(PortfolioContext);
    if (!context) {
        throw new Error('usePortfolioContext must be used within a PortfolioProvider');
    }
    return context;
};

export default PortfolioContext;

/**
 * useAppState - Hook لاستخدام AppStateManager في الشاشات
 * ========================================================
 * يوفر واجهة سهلة للوصول لحالة التطبيق المركزية
 */

import { useState, useEffect, useCallback } from 'react';
import { appStateManager, AppEvents } from '../services/AppStateManager';

/**
 * Hook للاستماع لحالة الاتصال
 */
export const useConnectionStatus = () => {
    const [isConnected, setIsConnected] = useState(appStateManager.isConnected);

    useEffect(() => {
        const unsubscribe = appStateManager.on(AppEvents.CONNECTION_STATUS_CHANGED, (data) => {
            setIsConnected(data.isConnected);
        });

        return unsubscribe;
    }, []);

    return isConnected;
};

/**
 * Hook للاستماع لحالة النظام
 */
export const useSystemStatus = () => {
    const [systemStatus, setSystemStatus] = useState(appStateManager.systemStatus);

    useEffect(() => {
        const unsubscribe = appStateManager.on(AppEvents.SYSTEM_STATUS_CHANGED, (data) => {
            setSystemStatus(data);
        });

        return unsubscribe;
    }, []);

    return systemStatus;
};

/**
 * Hook للاستماع لوضع التداول
 */
export const useTradingMode = () => {
    const [tradingMode, setTradingMode] = useState(appStateManager.tradingMode);

    useEffect(() => {
        const unsubscribe = appStateManager.on(AppEvents.TRADING_MODE_CHANGED, (data) => {
            setTradingMode(data.mode);
        });

        return unsubscribe;
    }, []);

    return tradingMode;
};

/**
 * Hook لجلب البيانات مع إدارة الحالة
 */
export const useDataFetch = (fetchFunction, dependencies = []) => {
    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [refreshing, setRefreshing] = useState(false);

    const fetch = useCallback(async (forceRefresh = false) => {
        try {
            if (forceRefresh) {
                setRefreshing(true);
            } else {
                setLoading(true);
            }
            setError(null);

            const result = await fetchFunction(forceRefresh);
            setData(result);

        } catch (err) {
            setError(appStateManager.getUserErrorMessage(err));
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    }, [fetchFunction]);

    // جلب البيانات عند التحميل
    useEffect(() => {
        fetch(false);
    }, dependencies);

    // الاستماع لأحداث التحديث
    useEffect(() => {
        const unsubscribe = appStateManager.on(AppEvents.FORCE_REFRESH, () => {
            fetch(true);
        });

        return unsubscribe;
    }, [fetch]);

    const refresh = useCallback(() => fetch(true), [fetch]);

    return { data, loading, error, refreshing, refresh };
};

/**
 * Hook للمحفظة
 */
export const usePortfolio = () => {
    const { data, loading, error, refreshing, refresh } = useDataFetch(
        (forceRefresh) => appStateManager.fetchPortfolio(forceRefresh),
        [appStateManager.userId, appStateManager.tradingMode]
    );

    // الاستماع لتحديثات المحفظة
    useEffect(() => {
        const unsubscribe = appStateManager.on(AppEvents.PORTFOLIO_UPDATED, (newData) => {
            // البيانات ستتحدث تلقائياً من خلال useDataFetch
        });

        return unsubscribe;
    }, []);

    return { portfolio: data, loading, error, refreshing, refresh };
};

