/**
 * Admin Dashboard - لوحة تحكم الأدمن المُبسطة
 * ============================================
 * ✅ تحكم موحد في النظام الخلفي (Group A + Group B + ML)
 * ✅ عرض حالة الأنظمة الفرعية (للمراقبة فقط)
 * ✅ سجل الأخطاء الحقيقي من Backend
 * ✅ إعادة ضبط Demo
 *
 * ⚠️ ملاحظة مهمة:
 * - النظام الخلفي واحد يدير كل شيء
 * - لا يوجد تحكم منفصل في Group A أو B
 * - الأنظمة الفرعية للعرض فقط
 */

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
    View,
    Text,
    ScrollView,
    TouchableOpacity,
    RefreshControl,
    StyleSheet,
    DeviceEventEmitter,
    ActivityIndicator,
} from 'react-native';
import { theme } from '../theme/theme';
import ModernCard from '../components/ModernCard';
import { useBackHandler } from '../utils/BackHandlerUtil';
import ToastService from '../services/ToastService';
import DatabaseApiService from '../services/DatabaseApiService';
import { AlertService } from '../components/CustomAlert';
import { useTradingModeContext } from '../context/TradingModeContext';
import { appStateManager, AppEvents } from '../services/AppStateManager';
import { AdminDashboardSkeleton } from '../components/SkeletonLoader';
import { hapticWarning, hapticError, hapticSuccess } from '../utils/HapticFeedback';

const AdminDashboard = ({ onBack, navigation, user }) => {
    // ==================== التحقق من الصلاحيات ====================
    const isAdmin = user && user.user_type === 'admin';

    const {
        isConnected: contextIsConnected,
        updateConnectionStatus,
    } = useTradingModeContext();

    // ==================== State ====================
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);
    const [lastUpdated, setLastUpdated] = useState(null);
    const isMountedRef = useRef(true);
    const isServerConnected = contextIsConnected;

    // ✅ حالة النظام الخلفي الفعلية (المصدر الوحيد للحقيقة)
    const [systemStatus, setSystemStatus] = useState({
        is_running: false,
        status: 'stopped',
        uptime: 0,
        uptime_formatted: null,
        started_at: null,
        pid: null,
    });

    // ✅ حالة الأنظمة الفرعية (للعرض فقط)
    const [subsystems, setSubsystems] = useState({
        groupA: { coins_analyzed: 0, successful_coins: 0, last_run: null },
        groupB: { active_trades: 0, monitored_coins: 0, last_cycle: null },
        ml: { is_ready: false, progress_pct: 0, total_samples: 0, required_samples: 500 },
    });

    // ✅ سجل الأخطاء
    const [errors, setErrors] = useState({
        count: 0,
        critical_count: 0,
        recent: [],
    });

    // ✅ حالة التحميل للأزرار
    const [actionLoading, setActionLoading] = useState({
        system: false,
        resetDemo: false,
    });

    useBackHandler(() => { onBack && onBack(); });

    // ==================== جلب البيانات ====================
    const fetchAllData = useCallback(async (silent = false) => {
        if (!isMountedRef.current || !isAdmin) {return;}

        try {
            if (!silent) {setLoading(true);}

            // 1️⃣ جلب حالة النظام الخلفي الفعلية (الأهم - المصدر الوحيد للحقيقة)
            try {
                const response = await DatabaseApiService.getBackgroundSystemStatus?.();
                if (isMountedRef.current && response?.success) {
                    const data = response.data || response;
                    setSystemStatus({
                        is_running: data.is_running || false,
                        status: data.status || 'stopped',
                        uptime: data.uptime || 0,
                        uptime_formatted: data.uptime_formatted || null,
                        started_at: data.started_at || null,
                        pid: data.pid || null,
                    });
                    updateConnectionStatus(true);
                }
            } catch (e) {
                console.log('[AdminDashboard] System status error:', e.message);
                updateConnectionStatus(false);
            }

            // 2️⃣ جلب حالة الأنظمة الفرعية (للعرض فقط)
            try {
                const mlResponse = await DatabaseApiService.getSystemMLStatus?.('demo');
                if (isMountedRef.current && mlResponse?.success) {
                    setSubsystems(prev => ({
                        ...prev,
                        ml: {
                            is_ready: mlResponse.ml?.is_ready || false,
                            progress_pct: mlResponse.ml?.progress_pct || 0,
                            total_samples: mlResponse.ml?.total_samples || 0,
                            required_samples: mlResponse.ml?.required_samples || 500,
                        },
                        groupB: {
                            ...prev.groupB,
                            active_trades: mlResponse.active_positions?.length || 0,
                        },
                    }));
                }
            } catch (e) {
                console.log('[AdminDashboard] ML status error:', e.message);
            }

            // 3️⃣ جلب حالة Group A و B
            try {
                const [groupARes, groupBRes] = await Promise.all([
                    DatabaseApiService.getGroupAStatus?.(),
                    DatabaseApiService.getGroupBStatus?.(),
                ]);

                if (isMountedRef.current) {
                    if (groupARes?.success !== false) {
                        const dataA = groupARes?.data || groupARes || {};
                        setSubsystems(prev => ({
                            ...prev,
                            groupA: {
                                coins_analyzed: dataA.coins_analyzed || 0,
                                successful_coins: dataA.successful_coins || 0,
                                last_run: dataA.last_run || null,
                            },
                        }));
                    }
                    if (groupBRes?.success !== false) {
                        const dataB = groupBRes?.data || groupBRes || {};
                        setSubsystems(prev => ({
                            ...prev,
                            groupB: {
                                ...prev.groupB,
                                monitored_coins: dataB.monitored_coins || 0,
                                last_cycle: dataB.last_cycle || null,
                            },
                        }));
                    }
                }
            } catch (e) {
                console.log('[AdminDashboard] Group status error:', e.message);
            }

            // 4️⃣ جلب الأخطاء
            try {
                const errorsRes = await DatabaseApiService.getBackgroundErrors?.(5);
                if (isMountedRef.current && errorsRes?.success) {
                    setErrors({
                        count: errorsRes.count || 0,
                        critical_count: errorsRes.errors?.filter(e => e.level === 'critical')?.length || 0,
                        recent: errorsRes.errors?.slice(0, 3) || [],
                    });
                }
            } catch (e) {
                console.log('[AdminDashboard] Errors fetch error:', e.message);
            }

            if (isMountedRef.current) {
                setLastUpdated(new Date());
            }

        } catch (err) {
            if (isMountedRef.current) {
                hapticError();
                updateConnectionStatus(false);
            }
        } finally {
            if (isMountedRef.current) {
                setLoading(false);
                setRefreshing(false);
            }
        }
    }, [isAdmin, updateConnectionStatus]);

    // ==================== Effects ====================
    useEffect(() => {
        if (!isAdmin) {
            ToastService.showError('الوصول مرفوض - هذه الصفحة للأدمن فقط');
            navigation?.navigate('Dashboard');
        }
    }, [isAdmin, navigation]);

    useEffect(() => {
        isMountedRef.current = true;
        if (!isAdmin) {return;}

        fetchAllData();

        // Polling كل 10 ثواني
        const interval = setInterval(() => {
            if (isMountedRef.current) {fetchAllData(true);}
        }, 10000);

        const resumeListener = DeviceEventEmitter.addListener('APP_RESUMED_FROM_BACKGROUND', () => {
            if (isMountedRef.current) {fetchAllData(true);}
        });

        return () => {
            isMountedRef.current = false;
            clearInterval(interval);
            resumeListener.remove();
        };
    }, [isAdmin, fetchAllData]);

    // ==================== Actions ====================
    // ✅ تشغيل/إيقاف النظام الخلفي الموحد (يتحكم في Group A + Group B + ML)
    const handleToggleSystem = async () => {
        // منع الضغط المتكرر
        if (actionLoading.system) {return;}

        const isRunning = systemStatus.is_running;
        const action = isRunning ? 'إيقاف' : 'تشغيل';

        AlertService.warning(
            `${action} نظام التداول`,
            isRunning
                ? '⚠️ سيتم إيقاف نظام التداول بالكامل:\n• المجموعة A (اختيار العملات)\n• المجموعة B (التداول الآلي)\n• نظام التعلم الآلي\n\nهل أنت متأكد؟'
                : '✅ سيتم تشغيل نظام التداول بالكامل:\n• المجموعة A (اختيار العملات)\n• المجموعة B (التداول الآلي)\n• نظام التعلم الآلي\n\nهل تريد المتابعة؟',
            [
                { text: 'إلغاء', style: 'cancel' },
                {
                    text: action,
                    style: isRunning ? 'destructive' : 'default',
                    onPress: async () => {
                        try {
                            // 1️⃣ تفعيل حالة التحميل
                            setActionLoading(prev => ({ ...prev, system: true }));

                            // 2️⃣ تحديث الحالة مؤقتاً (Optimistic Update)
                            setSystemStatus(prev => ({ ...prev, status: 'pending' }));

                            // 3️⃣ تنفيذ الأمر
                            const response = isRunning
                                ? await DatabaseApiService.stopBackgroundSystem?.()
                                : await DatabaseApiService.startBackgroundSystem?.();

                            // 4️⃣ معالجة النتيجة
                            if (response?.success) {
                                hapticSuccess();

                                // ✅ عرض تحذير الصفقات المفتوحة إذا كان إيقاف
                                if (isRunning && response?.warning && response?.open_positions > 0) {
                                    ToastService.showWarning(response.warning, 5000);
                                }

                                ToastService.showSuccess(`تم ${action} النظام بنجاح`);

                                // ✅ إشعار جميع الشاشات بتغيير حالة النظام
                                appStateManager.updateSystemStatus({
                                    is_running: !isRunning,
                                    status: isRunning ? 'stopped' : 'running',
                                });

                                // تحديث الحالة من الخادم
                                await fetchAllData(true);
                            } else {
                                hapticError();
                                setSystemStatus(prev => ({ ...prev, status: isRunning ? 'running' : 'stopped' }));
                                ToastService.showError(response?.error || `فشل ${action} النظام`);
                            }
                        } catch (e) {
                            hapticError();
                            setSystemStatus(prev => ({ ...prev, status: isRunning ? 'running' : 'stopped' }));
                            // ✅ رسالة خطأ واضحة للمستخدم
                            const errorMsg = appStateManager.getUserErrorMessage(e);
                            ToastService.showError(errorMsg);
                        } finally {
                            setActionLoading(prev => ({ ...prev, system: false }));
                        }
                    },
                },
            ]
        );
    };

    // ✅ إيقاف الطوارئ
    const handleEmergencyStop = async () => {
        // منع الضغط المتكرر
        if (actionLoading.system) {return;}

        AlertService.warning(
            '🚨 إيقاف الطوارئ',
            'سيتم إيقاف النظام بالقوة فوراً!\n\nسيتم إيقاف:\n• جميع عمليات التداول\n• جميع الأنظمة الفرعية\n\n⚠️ هذا الإجراء لا يمكن التراجع عنه.',
            [
                { text: 'إلغاء', style: 'cancel' },
                {
                    text: '🚨 إيقاف فوري',
                    style: 'destructive',
                    onPress: async () => {
                        try {
                            // 1️⃣ تفعيل حالة التحميل
                            setActionLoading(prev => ({ ...prev, system: true }));
                            setSystemStatus(prev => ({ ...prev, status: 'stopping' }));

                            // 2️⃣ تنفيذ الأمر
                            const response = await DatabaseApiService.emergencyStopBackgroundSystem?.();

                            // 3️⃣ معالجة النتيجة
                            if (response?.success) {
                                hapticWarning();
                                ToastService.showSuccess('تم إيقاف الطوارئ بنجاح');
                                await fetchAllData(true);
                            } else {
                                hapticError();
                                ToastService.showError(response?.error || 'فشل إيقاف الطوارئ');
                                await fetchAllData(true);
                            }
                        } catch (e) {
                            hapticError();
                            ToastService.showError('فشل الاتصال');
                            await fetchAllData(true);
                        } finally {
                            setActionLoading(prev => ({ ...prev, system: false }));
                        }
                    },
                },
            ]
        );
    };

    // ✅ إعادة ضبط Demo
    const handleResetDemo = async () => {
        // منع الضغط المتكرر
        if (actionLoading.resetDemo) {return;}

        AlertService.warning(
            '🔄 إعادة ضبط الحساب التجريبي',
            'سيتم حذف جميع الصفقات وإعادة الرصيد إلى $1,000.\n\nهل أنت متأكد؟',
            [
                { text: 'إلغاء', style: 'cancel' },
                {
                    text: 'إعادة ضبط',
                    style: 'destructive',
                    onPress: async () => {
                        try {
                            setActionLoading(prev => ({ ...prev, resetDemo: true }));
                            const response = await DatabaseApiService.resetDemoAccount?.();

                            if (response?.success) {
                                hapticSuccess();
                                ToastService.showSuccess('تم إعادة ضبط الحساب بنجاح');
                                await fetchAllData(true);
                            } else {
                                hapticError();
                                ToastService.showError(response?.error || 'فشل إعادة الضبط');
                            }
                        } catch (e) {
                            hapticError();
                            ToastService.showError('فشل الاتصال');
                        } finally {
                            setActionLoading(prev => ({ ...prev, resetDemo: false }));
                        }
                    },
                },
            ]
        );
    };

    // ==================== Helpers ====================
    const formatUptime = (seconds) => {
        if (!seconds || seconds === 0) {return 'غير متاح';}
        const days = Math.floor(seconds / 86400);
        const hours = Math.floor((seconds % 86400) / 3600);
        const minutes = Math.floor((seconds % 3600) / 60);
        if (days > 0) {return `${days} يوم ${hours} ساعة`;}
        if (hours > 0) {return `${hours} ساعة ${minutes} دقيقة`;}
        if (minutes > 0) {return `${minutes} دقيقة`;}
        return `${seconds} ثانية`;
    };

    const formatTime = (dateString) => {
        if (!dateString) {return 'غير متاح';}
        try {
            return new Date(dateString).toLocaleTimeString('ar-SA');
        } catch {
            return 'غير متاح';
        }
    };

    const renderStatItem = (label, value, color = theme.colors.text) => (
        <View style={styles.statItem}>
            <Text style={styles.statLabel}>{label}</Text>
            <Text style={[styles.statValue, { color }]}>{value}</Text>
        </View>
    );

    // ==================== Render ====================
    if (!isAdmin) {return null;}
    if (loading && !refreshing) {return <View style={styles.container}><AdminDashboardSkeleton /></View>;}

    const isSystemRunning = systemStatus.is_running;
    const mlProgress = subsystems.ml.progress_pct || 0;

    return (
        <View style={styles.container}>
            <ScrollView
                style={styles.content}
                refreshControl={
                    <RefreshControl
                        refreshing={refreshing}
                        onRefresh={() => { setRefreshing(true); fetchAllData(); }}
                        tintColor={theme.colors.primary}
                    />
                }
                showsVerticalScrollIndicator={false}
            >
                {/* ═══════════════ شريط الحالة الموحد ═══════════════ */}
                <View style={styles.statusBar}>
                    <View style={styles.statusBarItem}>
                        <View style={[styles.statusDot, { backgroundColor: isServerConnected ? theme.colors.success : theme.colors.error }]} />
                        <Text style={styles.statusBarLabel}>الخادم:</Text>
                        <Text style={[styles.statusBarValue, { color: isServerConnected ? theme.colors.success : theme.colors.error }]}>
                            {isServerConnected ? 'متصل' : 'غير متصل'}
                        </Text>
                    </View>
                    <View style={styles.statusBarDivider} />
                    <View style={styles.statusBarItem}>
                        <View style={[styles.statusDot, { backgroundColor: isSystemRunning ? theme.colors.success : theme.colors.error }]} />
                        <Text style={styles.statusBarLabel}>النظام:</Text>
