import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    ActivityIndicator,
    RefreshControl,
    I18nManager,
    TouchableOpacity,
    Image,
} from 'react-native';
// ActivityIndicator موجود بالفعل
import AsyncStorage from '@react-native-async-storage/async-storage';
