import { InfoMessage } from './components/StatusMessage';
import ResendButton from './components/ResendButton';
import OTPService from '../../services/OTPService';
import ToastService from '../../services/ToastService';
import { theme } from '../../theme/theme';

const { width, height } = Dimensions.get('window');

/**
 * شاشة تأكيد إرسال OTP
 * @param {object} navigation - التنقل
 * @param {object} route - معاملات الشاشة
 */
const OTPSentScreen = ({ navigation, route }) => {
  const { colors } = useTheme();
  const {
    email,
    phoneNumber,
    isPhone = false,
    operationType,
    additionalData = {},
    maskedEmail,
  } = route.params || {};

  // الحصول على رسائل العملية
  const operationMessages = OTPService.getOperationMessages(operationType);

  // تحديد الرسالة حسب طريقة التحقق
  const sentMessage = isPhone
    ? (operationMessages.sentMessagePhone || 'تم إرسال رمز التحقق إلى هاتفك')
    : (operationMessages.sentMessage || 'تم إرسال رمز التحقق إلى إيميلك');

  const subtitle = isPhone
    ? (operationMessages.subtitlePhone || 'تحقق من رسائل هاتفك')
    : (operationMessages.subtitle || 'تحقق من بريدك الإلكتروني');

  useEffect(() => {
    // تحديث عنوان الشاشة
    navigation.setOptions({
      title: operationMessages.title || 'تأكيد الإرسال',
    });
  }, [navigation, operationMessages]);

  // فتح تطبيق الإيميل
  const openEmailApp = () => {
    const emailApps = {
      ios: [
        'message://', // Mail app
        'googlegmail://', // Gmail
        'ms-outlook://', // Outlook
        'ymail://', // Yahoo Mail
      ],
      android: [
        'mailto:', // Default email
        'googlegmail://', // Gmail
        'ms-outlook://', // Outlook
      ],
    };

    const apps = Platform.OS === 'ios' ? emailApps.ios : emailApps.android;

    // محاولة فتح أول تطبيق متاح
    const tryOpenApp = (index = 0) => {
      if (index >= apps.length) {
        // إذا فشلت جميع المحاولات، فتح الإيميل العادي
        Linking.openURL(`mailto:${email}`);
        return;
      }

      Linking.canOpenURL(apps[index])
        .then(supported => {
          if (supported) {
            Linking.openURL(apps[index]);
          } else {
            tryOpenApp(index + 1);
          }
        })
        .catch(() => tryOpenApp(index + 1));
    };

    tryOpenApp();
  };

  // إعادة إرسال OTP
  const handleResend = async () => {
    try {
      const result = await OTPService.resendOTP(email, operationType, additionalData);

      if (result.success) {
        ToastService.success('تم إعادة إرسال الرمز بنجاح');
      } else {
        ToastService.error(result.message || 'فشل في إعادة الإرسال');
      }
    } catch (error) {
      console.error('خطأ في إعادة الإرسال:', error);
    }
  };

  // الانتقال إلى شاشة إدخال OTP
  const goToVerification = () => {
    navigation.navigate('OTPVerification', {
      email,
      phoneNumber,
      isPhone,
      operationType,
      additionalData,
      maskedEmail,
    });
  };

  // العودة للشاشة السابقة
  const goBack = () => {
    navigation.goBack();
  };

  const styles = StyleSheet.create({
    safeArea: {
      flex: 1,
      backgroundColor: theme.colors.background,
    },
    container: {
      flex: 1,
      backgroundColor: colors.background,
    },
    scrollContainer: {
      flexGrow: 1,
      justifyContent: 'center',
      padding: width * 0.05,
    },
    header: {
      alignItems: 'center',
      marginBottom: height * 0.04,
    },
    iconContainer: {
      width: width * 0.25,
      height: width * 0.25,
      borderRadius: width * 0.125,
      backgroundColor: colors.primary + '20',
      justifyContent: 'center',
      alignItems: 'center',
      marginBottom: 20,
    },
    title: {
      fontSize: width * 0.06,
      fontWeight: 'bold',
      color: colors.text,
      textAlign: 'center',
      marginBottom: 10,
    },
    subtitle: {
      fontSize: width * 0.04,
      color: colors.textSecondary,
      textAlign: 'center',
      lineHeight: 22,
    },
    emailContainer: {
      backgroundColor: colors.surface,
      borderRadius: 12,
      padding: 16,
      marginVertical: 20,
      borderLeftWidth: 4,
      borderLeftColor: colors.primary,
    },
    emailLabel: {
      fontSize: width * 0.035,
      color: colors.textSecondary,
      marginBottom: 4,
      textAlign: 'center',
    },
    emailText: {
      fontSize: width * 0.045,
      fontWeight: 'bold',
      color: colors.text,
      textAlign: 'center',
      fontFamily: 'monospace',
    },
    actionsContainer: {
      marginTop: 20,
    },
    primaryButton: {
      backgroundColor: colors.primary,
      borderRadius: 12,
      padding: 16,
      alignItems: 'center',
      marginBottom: 12,
    },
    primaryButtonText: {
      color: colors.surface,
      fontSize: width * 0.045,
      fontWeight: 'bold',
    },
    secondaryButton: {
      backgroundColor: colors.surface,
      borderRadius: 12,
      padding: 16,
      alignItems: 'center',
      marginBottom: 12,
      borderWidth: 1,
      borderColor: colors.border,
    },
    secondaryButtonText: {
      color: colors.text,
      fontSize: width * 0.04,
      fontWeight: '600',
    },
    resendContainer: {
      alignItems: 'center',
      marginTop: 20,
    },
    resendLabel: {
      fontSize: width * 0.035,
      color: colors.textSecondary,
      marginBottom: 12,
      textAlign: 'center',
    },
    backButton: {
      position: 'absolute',
      top: Platform.OS === 'ios' ? 50 : 20,
      right: 20,
      width: 40,
      height: 40,
      borderRadius: 20,
      backgroundColor: colors.surface,
      justifyContent: 'center',
      alignItems: 'center',
      elevation: 2,
      shadowColor: '#000',
      shadowOffset: { width: 0, height: 2 },
      shadowOpacity: 0.1,
      shadowRadius: 4,
    },
    infoContainer: {
      marginTop: 20,
    },
  });

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="light-content" backgroundColor={theme.colors.background} />
      <View style={styles.container}>
        {/* زر العودة */}
        <TouchableOpacity style={styles.backButton} onPress={goBack}>
          <Icon name="arrow-forward" size={24} color={colors.text} />
        </TouchableOpacity>

        <ScrollView
          contentContainerStyle={styles.scrollContainer}
          showsVerticalScrollIndicator={false}
        >
          {/* الرأس */}
          <View style={styles.header}>
            <View style={styles.iconContainer}>
              <Icon
                name={isPhone ? 'phone' : 'mark-email-read'}
                size={width * 0.12}
                color={colors.primary}
              />
            </View>
            <Text style={styles.title}>
              {operationMessages.title}
            </Text>
            <Text style={styles.subtitle}>
              {sentMessage}
