          </View>

          {/* عرض الإيميل أو الهاتف */}
          <View style={styles.emailContainer}>
            <Text style={styles.emailLabel}>
              تم الإرسال إلى:
            </Text>
            <Text style={styles.emailText}>
              {isPhone
                ? (maskedEmail || OTPService.maskPhone(phoneNumber))
                : (maskedEmail || OTPService.maskEmail(email))
              }
            </Text>
          </View>

          {/* الإجراءات */}
