/**
 * شاشة النجاح بعد التحقق من OTP
 * @param {object} navigation - التنقل
 * @param {object} route - معاملات الشاشة
 */
const OTPSuccessScreen = ({ navigation, route }) => {
  const { colors } = useTheme();
  const {
    email,
    operationType,
    additionalData = {},
    message,
    nextScreen = 'Dashboard',
    autoRedirect = true,
    redirectDelay = 3000,
  } = route.params || {};

  // الحالات المحلية
  const [countdown, setCountdown] = useState(Math.floor(redirectDelay / 1000));
  const [isRedirecting, setIsRedirecting] = useState(false);

  // تأثيرات الحركة - ✅ استخدام useRef لمنع إعادة الإنشاء
  const scaleValue = useRef(new Animated.Value(0)).current;
  const fadeValue = useRef(new Animated.Value(0)).current;
  const progressValue = useRef(new Animated.Value(0)).current;

  // الحصول على رسائل العملية
  const operationMessages = OTPService.getOperationMessages(operationType);

  useEffect(() => {
    // تشغيل تأثير الظهور
    startAnimations();

    // تحديث عنوان الشاشة
    navigation.setOptions({
      title: 'تم بنجاح',
      headerLeft: null, // إخفاء زر العودة
    });

    // منع العودة بزر الأندرويد
    const backHandler = BackHandler.addEventListener('hardwareBackPress', () => true);

    // بدء العداد التنازلي للتوجيه التلقائي
    if (autoRedirect) {
      startCountdown();
    }

    return () => {
      backHandler.remove();
    };
  }, []);

  // تشغيل تأثيرات الحركة
  const startAnimations = () => {
    Animated.parallel([
      Animated.spring(scaleValue, {
        toValue: 1,
        tension: 50,
        friction: 7,
        useNativeDriver: true,
      }),
      Animated.timing(fadeValue, {
        toValue: 1,
        duration: 800,
        useNativeDriver: true,
      }),
    ]).start();
  };

  // بدء العداد التنازلي مع شريط التقدم
  const startCountdown = () => {
    // ✅ تحريك شريط التقدم
    Animated.timing(progressValue, {
      toValue: 1,
      duration: redirectDelay,
      useNativeDriver: false,
    }).start();

    const timer = setInterval(() => {
      setCountdown(prev => {
        if (prev <= 1) {
          clearInterval(timer);
          handleRedirect();
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  // التوجيه للشاشة التالية
  const handleRedirect = async () => {
    if (isRedirecting) {return;}

    setIsRedirecting(true);

    // تحديد الشاشة التالية حسب نوع العملية
    switch (operationType) {
      case 'register':
        // ✅ المستخدم الجديد يذهب إلى الشاشة الرئيسية التي ستعرض Onboarding تلقائياً
        // لأن onboarding_completed لم يُحفظ بعد
        navigation.reset({
          index: 0,
          routes: [{ name: 'Dashboard' }],
        });
        break;

      case 'change_email':
        navigation.reset({
          index: 0,
          routes: [
            { name: 'Dashboard' },
            { name: 'Settings' },
          ],
        });
        break;

      case 'change_password':
        // تسجيل خروج تلقائي بعد تغيير كلمة المرور
        navigation.reset({
          index: 0,
          routes: [{ name: 'Login' }],
        });
        break;

      case 'reset_password':
        navigation.reset({
          index: 0,
          routes: [{ name: 'Login' }],
        });
        break;

      default:
        navigation.reset({
          index: 0,
          routes: [{ name: nextScreen || 'Dashboard' }],
        });
    }
  };

  // التوجيه الفوري
  const handleContinue = () => {
    handleRedirect();
  };

  // الحصول على الرسالة المناسبة
  const getSuccessMessage = () => {
    if (message) {return message;}

    switch (operationType) {
      case 'register':
        return 'تم إنشاء حسابك بنجاح! مرحباً بك في 1B Trading';
      case 'change_email':
        return `تم تغيير إيميلك بنجاح إلى ${additionalData.newEmail || email}`;
      case 'change_password':
        return 'تم تغيير كلمة المرور بنجاح. يرجى تسجيل الدخول مرة أخرى';
      case 'reset_password':
        return 'تم إعادة تعيين كلمة المرور بنجاح. يمكنك الآن تسجيل الدخول';
      default:
        return operationMessages.successMessage || 'تم التحقق بنجاح!';
    }
  };

  // الحصول على النص التوضيحي
  const getSubtitle = () => {
    switch (operationType) {
      case 'register':
        return 'سنوجهك الآن لإعداد حسابك خطوة بخطوة';
      case 'change_email':
        return 'تم تحديث عنوان إيميلك في حسابك';
      case 'change_password':
        return 'من أجل الأمان، يرجى تسجيل الدخول بكلمة المرور الجديدة';
      case 'reset_password':
        return 'يمكنك الآن تسجيل الدخول بكلمة المرور الجديدة';
      default:
        return 'تم إكمال العملية بنجاح';
    }
  };

  // الحصول على نص الزر
  const getButtonText = () => {
    switch (operationType) {
      case 'register':
        return 'ابدأ الإعداد';
      case 'change_email':
        return 'العودة للإعدادات';
      case 'change_password':
      case 'reset_password':
        return 'تسجيل الدخول';
      default:
        return 'المتابعة';
    }
  };

  // الحصول على أيقونة النجاح
  const getSuccessIcon = () => {
    switch (operationType) {
      case 'register':
        return 'person-add';
      case 'change_email':
        return 'email';
      case 'change_password':
      case 'reset_password':
        return 'lock';
      default:
        return 'check-circle';
    }
  };

  const styles = StyleSheet.create({
    safeArea: {
      flex: 1,
      backgroundColor: theme.colors.background,
    },
    container: {
      flex: 1,
      backgroundColor: colors.background,
      justifyContent: 'center',
      alignItems: 'center',
      padding: width * 0.05,
    },
    animatedContainer: {
      alignItems: 'center',
    },
    iconContainer: {
      width: width * 0.3,
      height: width * 0.3,
      borderRadius: width * 0.15,
      backgroundColor: colors.success + '20',
      justifyContent: 'center',
      alignItems: 'center',
      marginBottom: 30,
      elevation: 5,
      shadowColor: colors.success,
      shadowOffset: { width: 0, height: 4 },
      shadowOpacity: 0.3,
      shadowRadius: 8,
    },
    successIcon: {
      marginBottom: 10,
    },
    checkIcon: {
      position: 'absolute',
      bottom: -5,
      right: -5,
      backgroundColor: colors.success,
      borderRadius: 15,
      width: 30,
      height: 30,
      justifyContent: 'center',
      alignItems: 'center',
    },
    title: {
      fontSize: width * 0.07,
      fontWeight: 'bold',
      color: colors.text,
      textAlign: 'center',
      marginBottom: 15,
    },
    subtitle: {
      fontSize: width * 0.04,
      color: colors.textSecondary,
      textAlign: 'center',
      lineHeight: 24,
      marginBottom: 30,
    },
    messageContainer: {
      width: '100%',
      marginBottom: 30,
    },
    continueButton: {
      backgroundColor: colors.success,
      borderRadius: 12,
      paddingVertical: 16,
      paddingHorizontal: 32,
      minWidth: width * 0.6,
      alignItems: 'center',
      elevation: 3,
      shadowColor: colors.success,
      shadowOffset: { width: 0, height: 2 },
      shadowOpacity: 0.3,
      shadowRadius: 4,
    },
    continueButtonText: {
      color: colors.surface,
      fontSize: width * 0.045,
      fontWeight: 'bold',
    },
    countdownContainer: {
      marginTop: 20,
      alignItems: 'center',
    },
    countdownText: {
      fontSize: width * 0.035,
      color: colors.textSecondary,
      textAlign: 'center',
      marginLeft: 10,
    },
    logoContainer: {
      position: 'absolute',
      top: 40,
      alignItems: 'center',
      width: '100%',
    },
    successText: {
      fontSize: width * 0.04,
      color: colors.textSecondary,
      textAlign: 'center',
      lineHeight: 24,
      marginBottom: 40,
      paddingHorizontal: 20,
    },
    progressContainer: {
      width: '80%',
      alignItems: 'center',
      marginTop: 20,
    },
    progressBar: {
      width: '100%',
      height: 6,
      backgroundColor: colors.border,
      borderRadius: 3,
      overflow: 'hidden',
    },
    progressFill: {
      height: '100%',
      backgroundColor: colors.success,
      borderRadius: 3,
    },
    redirectInfo: {
      flexDirection: 'row',
      alignItems: 'center',
      marginTop: 15,
    },
  });

  // ✅ عرض شريط التقدم
  const progressWidth = progressValue.interpolate({
    inputRange: [0, 1],
    outputRange: ['0%', '100%'],
  });

  return (
    <SafeAreaView style={styles.safeArea}>
      <StatusBar barStyle="light-content" backgroundColor={theme.colors.background} />
      <View style={styles.container}>
        {/* ✅ شعار التطبيق */}
        <View style={styles.logoContainer}>
          <UnifiedBrandLogo variant="compact" />
        </View>

        <Animated.View
          style={[
            styles.animatedContainer,
            {
              transform: [{ scale: scaleValue }],
              opacity: fadeValue,
            },
          ]}
        >
          {/* أيقونة النجاح */}
          <View style={styles.iconContainer}>
            <Icon
              name="check-circle"
              size={width * 0.2}
              color={colors.success}
            />
          </View>

          {/* العنوان */}
          <Text style={styles.title}>
            {operationType === 'register' ? 'مرحباً بك!' : 'تم بنجاح!'}
          </Text>

          {/* رسالة النجاح */}
          <Text style={styles.successText}>
            {getSuccessMessage()}
          </Text>

          {/* ✅ شريط التقدم بدلاً من الأزرار */}
          {autoRedirect && (
            <View style={styles.progressContainer}>
              <View style={styles.progressBar}>
                <Animated.View
                  style={[
                    styles.progressFill,
                    { width: progressWidth },
                  ]}
                />
              </View>
              <View style={styles.redirectInfo}>
                <ActivityIndicator size="small" color={colors.success} />
                <Text style={styles.countdownText}>
                  جاري التوجيه... {countdown} ثانية
                </Text>
              </View>
            </View>
          )}
        </Animated.View>
      </View>
    </SafeAreaView>
  );
};

export default OTPSuccessScreen;

import React, { useState, useEffect, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Dimensions,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
  Alert,
  BackHandler,
  SafeAreaView,
  StatusBar,
} from 'react-native';
// ✅ Firebase Auth مُثبت - OTPService يتولى التحقق من SMS
import Icon from '../../components/CustomIcons';
import { useTheme } from '../../context/ThemeContext';
import OTPInput from './components/OTPInput';
import CountdownTimer from './components/CountdownTimer';
import ResendButton from './components/ResendButton';
import StatusMessage, { ErrorMessage, SuccessMessage } from './components/StatusMessage';
import OTPService from '../../services/OTPService';
import { theme } from '../../theme/theme';
import UnifiedBrandLogo from '../../components/UnifiedBrandLogo';

const { width, height } = Dimensions.get('window');

/**
 * شاشة إدخال OTP الموحدة - تدعم الإيميل و SMS (Firebase)
 * @param {object} navigation - التنقل
 * @param {object} route - معاملات الشاشة
 */
const OTPVerificationScreen = ({ navigation, route }) => {
  const { colors } = useTheme();
  const {
    email,
    phoneNumber,
    isPhone = false,
    operationType,
    additionalData = {},
    registrationData = {},
    maskedEmail,
    fromScreen = 'OTPSent',
  } = route.params || {};

  // الحالات المحلية
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [isLoading, setIsLoading] = useState(false);
  const [attempts, setAttempts] = useState(0);
  const [hasError, setHasError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  // Firebase Phone Auth State
  const [confirm, setConfirm] = useState(null);

  // المراجع
  const otpInputRef = useRef();
  const maxAttempts = 3;

  // الحصول على رسائل العملية
  const operationMessages = OTPService.getOperationMessages(operationType);

  useEffect(() => {
    // تحديث عنوان الشاشة
    navigation.setOptions({
      title: operationMessages.title || 'التحقق من الرمز',
    });

    // معالجة زر العودة في Android
    const backHandler = BackHandler.addEventListener('hardwareBackPress', handleBackPress);

    return () => {
      backHandler.remove();
    };
  }, [navigation, operationMessages]);

  // ✅ معالجة زر العودة - إلغاء OTP عند الخروج
  const handleBackPress = async () => {
    try {
      // إلغاء OTP النشط في Backend
      if (email && !isPhone) {
        await OTPService.cancelOTP(email, operationType);
      }
    } catch (error) {
      // Silent failure - لا نعيق المستخدم
      console.warn('Failed to cancel OTP on back:', error);
    }

    // الانتقال
    if (fromScreen === 'OTPSent') {
      navigation.goBack();
    } else {
      navigation.navigate('OTPSent', {
        email,
        phoneNumber,
        isPhone,
        operationType,
        additionalData,
        maskedEmail,
      });
    }
    return true;
  };

  // مسح الرسائل
  const clearMessages = () => {
    setHasError(false);
    setErrorMessage('');
    setSuccessMessage('');
  };

  // عرض رسالة خطأ
  const showError = (message) => {
    setHasError(true);
    setErrorMessage(message);
    setSuccessMessage('');

    // اهتزاز مكون OTP
    if (otpInputRef.current) {
      otpInputRef.current.shake();
    }
  };

  // عرض رسالة نجاح
  const showSuccess = (message) => {
    setHasError(false);
    setErrorMessage('');
    setSuccessMessage(message);
  };

  // تغيير قيم OTP
  const handleOtpChange = (newOtp) => {
    setOtp(newOtp);
    clearMessages();
  };

  // اكتمال إدخال OTP
  const handleOtpComplete = (otpCode) => {
    // منع الاستدعاء المتكرر أثناء التحميل
    if (isLoading) {return;}
    if (otpCode.length === 6) {
      verifyOTP(otpCode);
    }
  };

  // التحقق من OTP
  const verifyOTP = async (otpCode = null) => {
    const codeToVerify = otpCode || otp.join('');

    if (codeToVerify.length !== 6) {
      showError('يرجى إدخال رمز التحقق كاملاً (6 أرقام)');
      return;
    }

    if (!/^\d{6}$/.test(codeToVerify)) {
      showError('رمز التحقق يجب أن يحتوي على أرقام فقط');
      return;
    }

    setIsLoading(true);
    clearMessages();

    try {
      let result;

      // ✅ إذا كان تسجيل جديد: استخدم endpoint الجديد (سواء بريد أو SMS)
      const isRegistration = operationType === 'register' || operationType === 'REGISTER';
      if (isRegistration && registrationData && Object.keys(registrationData).length > 0) {
        // 🆕 التحقق من OTP وإنشاء الحساب
        const DatabaseApiService = require('../../services/DatabaseApiService').default;

        if (isPhone) {
          // 📱 التسجيل عبر SMS - التحقق من Firebase أولاً ثم إنشاء الحساب
          try {
            const phoneResult = await OTPService.verifyPhoneOTP(codeToVerify, {
              ...additionalData,
              ...registrationData,
            });

            if (phoneResult.success) {
              // Firebase تحقق بنجاح - الآن أنشئ الحساب في الخادم
              result = await DatabaseApiService.registerWithPhone({
                phone: registrationData.phone,
                username: registrationData.username,
                password: registrationData.password,
                fullName: registrationData.fullName,
                email: registrationData.email, // اختياري
                firebaseToken: phoneResult.data?.idToken,
              });
            } else {
              result = phoneResult;
            }
          } catch (phoneError) {
            console.error('خطأ في التحقق من SMS:', phoneError);
            result = { success: false, message: 'فشل التحقق من رقم الهاتف' };
          }
        } else {
          // 📧 التسجيل عبر البريد
          result = await DatabaseApiService.verifyRegistrationOTP({
            email: registrationData.email,
            otp_code: codeToVerify,
            username: registrationData.username,
            password: registrationData.password,
            phone: registrationData.phone,
            fullName: registrationData.fullName,
          });
        }
      } else {
        // التحقق لعمليات أخرى (تسجيل دخول، تغيير كلمة مرور، إلخ)
        if (isPhone) {
          // 📱 التحقق عبر SMS (Firebase)
          result = await OTPService.verifyPhoneOTP(codeToVerify, additionalData);
        } else {
          // 📧 التحقق عبر الإيميل
          result = await OTPService.verifyOTP(
            email,
            codeToVerify,
            operationType,
            additionalData
          );
        }
      }

      if (result.success) {
        showSuccess(result.message || operationMessages.successMessage);

        // ✅ إذا كان تسجيل جديد: حفظ الـ token وتسجيل الدخول تلقائياً
        const token = result.accessToken || result.access_token;
        const userId = result.userId || result.user_id;

        if (isRegistration && token && userId) {
          const TempStorageService = require('../../services/TempStorageService').default;

          // ✅ دالة حفظ مع Retry Logic (3 محاولات)
          const saveWithRetry = async (key, value, maxRetries = 3) => {
            for (let attempt = 1; attempt <= maxRetries; attempt++) {
              try {
                await TempStorageService.setItem(key, value);
                return true;
              } catch (err) {
                console.warn(`⚠️ محاولة ${attempt}/${maxRetries} لحفظ ${key} فشلت:`, err);
                if (attempt < maxRetries) {
                  await new Promise(resolve => setTimeout(resolve, 200 * attempt));
                }
              }
            }
            return false;
          };

          try {
            // حفظ بيانات المستخدم
            const userData = {
              id: userId,
              email: registrationData.email,
              username: registrationData.username,
              fullName: registrationData.fullName,
              user_type: 'user',
            };

            // ✅ حفظ بالترتيب مع Retry
            const saveResults = await Promise.all([
              saveWithRetry('userData', JSON.stringify(userData)),
              saveWithRetry('accessToken', token),
              saveWithRetry('isLoggedIn', 'true'),
              saveWithRetry('lastUserId', userId.toString()),
            ]);

            if (result.refreshToken || result.refresh_token) {
              await saveWithRetry('refreshToken', result.refreshToken || result.refresh_token);
            }

            // ✅ التحقق من نجاح الحفظ الأساسي
            const criticalSaveSuccess = saveResults[0] && saveResults[1] && saveResults[2];

            if (criticalSaveSuccess) {
              console.log('✅ تم حفظ بيانات المستخدم بعد التسجيل - userId:', userId);
            } else {
              console.warn('⚠️ بعض البيانات لم تُحفظ بشكل كامل:', saveResults);
            }

            // ✅ الانتقال مباشرة لشاشة النجاح مع البيانات الكاملة
            setTimeout(() => {
              navigation.replace('OTPSuccess', {
                email,
                phoneNumber,
                isPhone,
                operationType,
                additionalData: {
                  ...additionalData,
                  accessToken: token,
                  userId: userId,
                  registrationComplete: true,
                  storageSaveSuccess: criticalSaveSuccess,
                },
                registrationData: registrationData,
                message: result.message || operationMessages.successMessage,
                nextScreen: 'Dashboard',
              });
            }, 1500);

          } catch (saveError) {
            console.error('❌ خطأ حرج في حفظ بيانات المستخدم:', saveError);
            // ✅ حتى لو فشل الحفظ، ننتقل لشاشة النجاح مع البيانات في params
            setTimeout(() => {
              navigation.replace('OTPSuccess', {
                email,
                operationType,
                additionalData: {
                  accessToken: token,
                  userId: userId,
                  storageSaveSuccess: false,
                },
                registrationData: registrationData,
                message: result.message || operationMessages.successMessage,
                nextScreen: 'Dashboard',
              });
            }, 1500);
          }
        } else if (operationType === 'reset_password') {
          // ✅ استعادة كلمة المرور - التحقق من OTP والحصول على Reset Token
          const DatabaseApiService = require('../../services/DatabaseApiService').default;
          const verifyResult = await DatabaseApiService.verifyResetOTP(email, codeToVerify);

          if (verifyResult.success && verifyResult.reset_token) {
            showSuccess(verifyResult.message || 'تم التحقق بنجاح');
            setTimeout(() => {
              navigation.navigate('NewPassword', {
                email: email,
                resetToken: verifyResult.reset_token,
                verified: true,
              });
            }, 1000);
          } else {
            showError(verifyResult.message || 'فشل التحقق من الرمز');
            setOtp(['', '', '', '', '', '']);
          }
        } else {
          // عمليات أخرى (ليست تسجيل أو استعادة كلمة مرور)
          setTimeout(() => {
            navigation.replace('OTPSuccess', {
              email,
              phoneNumber,
              isPhone,
              operationType,
              additionalData: {
                ...additionalData,
                accessToken: token,
                userId: userId,
              },
              message: result.message || operationMessages.successMessage,
              nextScreen: operationMessages.nextScreen,
            });
          }, 1500);
        }

      } else {
        // ✅ استخدام remaining_attempts من Backend إذا متاح
        const serverRemaining = result.remaining_attempts;
        const isMaxExceeded = result.code === 'MAX_ATTEMPTS_EXCEEDED' || serverRemaining === 0;

        if (isMaxExceeded) {
          showError('تجاوزت الحد الأقصى (5 محاولات). اضغط "إعادة إرسال" أسفل الشاشة للحصول على رمز جديد.');

          // مسح OTP وتعطيل الإدخال مؤقتاً
          setOtp(['', '', '', '', '', '']);

          // العودة لشاشة الإرسال بعد 3 ثوان
          setTimeout(() => {
            navigation.navigate('OTPSent', {
              email,
              phoneNumber,
              isPhone,
              operationType,
              additionalData,
              maskedEmail,
            });
          }, 3000);

        } else {
          // ✅ عرض رسالة الخطأ التفصيلية من Backend
          const errorMsg = result.message || 'رمز التحقق غير صحيح';
          showError(errorMsg);

          // مسح OTP للمحاولة التالية
          setOtp(['', '', '', '', '', '']);

          // التركيز على أول حقل
          setTimeout(() => {
            if (otpInputRef.current) {
              otpInputRef.current.focus();
            }
          }, 500);
        }
      }

    } catch (error) {
