                if (isMountedRef.current) {
                    setLoading(false);
                }
                return;
            }

            if (!isMountedRef.current) {return;}

            await DatabaseApiService.initialize();

            if (!isMountedRef.current) {return;}

            const apiData = await DatabaseApiService.getSettings(
                user.id,
                isAdmin ? currentViewMode : null
