                    position_size_percentage: apiSettings.positionSizePercentage || apiSettings.position_size_percentage || 10.0,
                    take_profit_pct: apiSettings.takeProfitPercentage || apiSettings.take_profit_pct || 5.0,
                    stop_loss_pct: apiSettings.stopLossPercentage || apiSettings.stop_loss_pct || 2.0,
                    trailing_distance: apiSettings.trailingDistance || apiSettings.trailing_distance || 3.0,
                    max_positions: apiSettings.maxConcurrentTrades || apiSettings.max_positions || 5,
                    trading_enabled: apiSettings.tradingEnabled ?? apiSettings.trading_enabled ?? false,
