                                maximumValue={10}
                                step={1}
                                unit=""
                            />
                        </ModernCard>
                    </>
                )}

                <TouchableOpacity
                    style={styles.advancedButton}
                    onPress={() => {
                        setShowAdvanced(!showAdvanced);
                        hapticLight();
                    }}
                    activeOpacity={0.7}
                >
                    <Icon name={showAdvanced ? 'chevron-up' : 'chevron-down'} size={20} color={theme.colors.primary} />
                    <Text style={styles.advancedButtonText}>
                        {showAdvanced ? 'إخفاء الإعدادات المتقدمة' : 'إظهار الإعدادات المتقدمة'}
                    </Text>
                </TouchableOpacity>

                {hasChanges && (
                    <View style={styles.actionButtons}>
                        <TouchableOpacity
                            style={[styles.button, styles.resetButton]}
                            onPress={handleReset}
                            activeOpacity={0.8}
                        >
                            <Icon name="refresh" size={18} color={theme.colors.text} />
                            <Text style={styles.resetButtonText}>إعادة تعيين</Text>
                        </TouchableOpacity>

                        <TouchableOpacity
                            style={[styles.button, styles.saveButton]}
                            onPress={saveSettings}
                            disabled={saving}
                            activeOpacity={0.8}
                        >
                            {saving ? (
                                <ActivityIndicator size="small" color={theme.colors.background} />
                            ) : (
                                <>
                                    <Icon name="check" size={18} color={theme.colors.background} />
                                    <Text style={styles.saveButtonText}>حفظ التغييرات</Text>
                                </>
                            )}
                        </TouchableOpacity>
                    </View>
                )}
            </ScrollView>
        </SafeAreaView>
    );
};

