/**
 * نظام تسجيل موحد للأخطاء والرسائل البرمجية
 *
 * الغرض:
 * - تسجيل جميع رسائل الكونسول البرمجية في ملف موحد
 * - رسائل الأخطاء البرمجية (للمطور) → تُسجل في الملف
 * - رسائل الأخطاء للمستخدم → تظهر في الواجهة فقط
 */

import RNFS from 'react-native-fs';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';
import unifiedConnectionService from './UnifiedConnectionService';

class LoggerService {
    constructor() {
        this.logFilePath = `${RNFS.DocumentDirectoryPath}/app_logs.txt`;
        this.maxLogSize = 5 * 1024 * 1024; // 5MB
        this.isEnabled = true; // يمكن تعطيله في الإنتاج

        // ✅ إعدادات إرسال السجلات للخادم
        this.sendToServer = true; // تفعيل الإرسال للخادم
        this.logBuffer = []; // buffer لتجميع السجلات
        this.maxBufferSize = 10; // عدد السجلات قبل الإرسال
        this.flushInterval = 30000; // إرسال كل 30 ثانية
        this.userId = null;
        this.deviceInfo = null;

        // بدء timer للإرسال الدوري
        this._startFlushTimer();
        this._loadUserInfo();
    }

    /**
     * تحميل معلومات المستخدم
     */
    async _loadUserInfo() {
        try {
            const userId = await AsyncStorage.getItem('userId');
            this.userId = userId || 'guest';

            // جمع معلومات الجهاز
            const { Platform, Dimensions } = require('react-native');
            this.deviceInfo = `${Platform.OS}/${Platform.Version}`;
        } catch (error) {
            // تجاهل الخطأ
        }
    }

    /**
     * بدء timer للإرسال الدوري
     */
    _startFlushTimer() {
        this.flushTimer = setInterval(() => {
            this._flushLogsToServer();
        }, this.flushInterval);
    }

    /**
     * إيقاف timer
     */
    _stopFlushTimer() {
        if (this.flushTimer) {
            clearInterval(this.flushTimer);
            this.flushTimer = null;
        }
    }

    /**
     * تسجيل رسالة معلوماتية (للمطور)
     */
    async info(message, context = '') {
        const logEntry = this._formatLog('INFO', message, context);
        await this._writeToFile(logEntry);
        await this._addToBuffer('INFO', message, context);
        if (__DEV__) {
            console.log(logEntry);
        }
    }

    /**
     * تسجيل رسالة تحذير (للمطور)
     */
    async warn(message, context = '') {
        const logEntry = this._formatLog('WARN', message, context);
        await this._writeToFile(logEntry);
        await this._addToBuffer('WARN', message, context);
        if (__DEV__) {
            console.warn(logEntry);
        }
    }

    /**
     * تسجيل خطأ برمجي (للمطور)
     */
    async error(message, error = null, context = '') {
        const errorDetails = error ? `\n${error.stack || error.message || error}` : '';
        const logEntry = this._formatLog('ERROR', message + errorDetails, context);
        await this._writeToFile(logEntry);
        await this._addToBuffer('ERROR', message + errorDetails, context, true); // إرسال فوري
        if (__DEV__) {
            console.error(logEntry);
        }
    }

    /**
     * تسجيل خطأ حرج (للمطور)
     */
    async critical(message, error = null, context = '') {
        const errorDetails = error ? `\n${error.stack || error.message || error}` : '';
        const logEntry = this._formatLog('CRITICAL', message + errorDetails, context);
        await this._writeToFile(logEntry);
        await this._addToBuffer('CRITICAL', message + errorDetails, context, true); // إرسال فوري
        console.error('🔴 CRITICAL:', logEntry);
    }

    /**
     * تسجيل رسالة debug (للمطور فقط)
     */
    async debug(message, context = '') {
        if (!__DEV__) {return;} // فقط في وضع التطوير
        const logEntry = this._formatLog('DEBUG', message, context);
        await this._writeToFile(logEntry);
        console.log(logEntry);
    }

    /**
     * تنسيق رسالة السجل
     */
    _formatLog(level, message, context) {
        const timestamp = new Date().toISOString();
        const contextStr = context ? ` [${context}]` : '';
        return `[${timestamp}] ${level}${contextStr}: ${message}`;
    }

    /**
     * كتابة السجل في الملف
     */
    async _writeToFile(logEntry) {
        if (!this.isEnabled) {return;}

        try {
            // التحقق من حجم الملف
            const fileExists = await RNFS.exists(this.logFilePath);
            if (fileExists) {
                const stats = await RNFS.stat(this.logFilePath);
                if (stats.size > this.maxLogSize) {
                    // إنشاء نسخة احتياطية وحذف الملف القديم
                    const backupPath = `${this.logFilePath}.old`;
                    await RNFS.moveFile(this.logFilePath, backupPath);
                }
            }

            // إضافة السجل للملف
            await RNFS.appendFile(this.logFilePath, logEntry + '\n', 'utf8');
        } catch (error) {
            // في حالة فشل الكتابة، نعرض في الكونسول فقط
            if (__DEV__) {
                console.error('Failed to write log:', error);
            }
        }
    }

    /**
     * قراءة السجلات (للمطور)
     */
    async readLogs() {
        try {
            const fileExists = await RNFS.exists(this.logFilePath);
            if (!fileExists) {
                return 'No logs available';
            }
            return await RNFS.readFile(this.logFilePath, 'utf8');
        } catch (error) {
            return `Error reading logs: ${error.message}`;
        }
    }

    /**
     * مسح السجلات
     */
    async clearLogs() {
        try {
            const fileExists = await RNFS.exists(this.logFilePath);
            if (fileExists) {
                await RNFS.unlink(this.logFilePath);
            }
            return true;
        } catch (error) {
            console.error('Failed to clear logs:', error);
            return false;
        }
    }

    /**
     * الحصول على مسار الملف
     */
    getLogFilePath() {
        return this.logFilePath;
    }

    /**
     * تفعيل/تعطيل التسجيل
     */
    setEnabled(enabled) {
        this.isEnabled = enabled;
    }

    /**
     * ✅ إضافة سجل إلى buffer
     */
    async _addToBuffer(level, message, context, immediate = false) {
        if (!this.sendToServer) {return;}

        const logEntry = {
            level,
            message,
            context,
            timestamp: new Date().toISOString(),
            userId: this.userId,
            device: this.deviceInfo,
        };

        this.logBuffer.push(logEntry);

        // إرسال فوري للأخطاء الحرجة
        if (immediate) {
            await this._flushLogsToServer();
        }
        // أو إرسال عند امتلاء الـ buffer
        else if (this.logBuffer.length >= this.maxBufferSize) {
            await this._flushLogsToServer();
        }
    }

    /**
     * ✅ إرسال السجلات المتراكمة للخادم
     */
    async _flushLogsToServer() {
        if (!this.sendToServer || this.logBuffer.length === 0) {return;}

        const logs = [...this.logBuffer];
        this.logBuffer = []; // تفريغ الـ buffer

        try {
            const baseURL = unifiedConnectionService.getBaseURL();

            await axios.post(`${baseURL}/api/client-logs/batch`, {
                logs,
            }, {
                timeout: 5000,
                headers: { 'Content-Type': 'application/json' },
            });

            // نجح الإرسال - لا حاجة لتسجيل
        } catch (error) {
            // فشل الإرسال - إعادة السجلات للـ buffer
            this.logBuffer = [...logs, ...this.logBuffer];

            // حذف السجلات القديمة جداً لتجنب امتلاء الذاكرة
            if (this.logBuffer.length > 100) {
                this.logBuffer = this.logBuffer.slice(-50);
            }
        }
    }

    /**
     * ✅ إرسال فوري للسجلات (للاستخدام عند إغلاق التطبيق)
     */
    async flush() {
        await this._flushLogsToServer();
    }

    /**
     * ✅ تفعيل/تعطيل الإرسال للخادم
     */
    setSendToServer(enabled) {
        this.sendToServer = enabled;
        if (!enabled) {
            this._stopFlushTimer();
        } else {
            this._startFlushTimer();
        }
    }

    /**
     * ✅ تنظيف الموارد
     */
    cleanup() {
        this._stopFlushTimer();
        this._flushLogsToServer(); // إرسال أي سجلات متبقية
    }
}

// تصدير instance واحد
export default new LoggerService();

/**
 * خدمة الإشعارات باستخدام Firebase Cloud Messaging
 * تدير إرسال واستقبال الإشعارات للتطبيق
 * ✅ مع دعم Deep Linking للتنقل من الإشعارات
 */

import { Alert } from 'react-native';
import messaging from '@react-native-firebase/messaging';
import TempStorageService from './TempStorageService';

// ✅ مرجع التنقل للوصول من خارج React Components
let navigationRef = null;

class NotificationService {
  constructor() {
    this.fcmToken = null;
    this.isInitialized = false;
    this.pendingNotification = null; // إشعار معلق للتنقل بعد تحميل التطبيق
  }

  /**
   * ✅ تعيين مرجع التنقل (يُستدعى من App.js)
   */
  setNavigationRef(ref) {
    navigationRef = ref;
    // إذا كان هناك إشعار معلق، نفذ التنقل الآن
    if (this.pendingNotification) {
      this.handleNotificationAction(this.pendingNotification);
      this.pendingNotification = null;
    }
  }

  /**
   * تهيئة خدمة الإشعارات
   */
  async initialize() {
    try {
      // طلب الإذن للإشعارات
      const authStatus = await messaging().requestPermission();
      const enabled =
        authStatus === messaging.AuthorizationStatus.AUTHORIZED ||
        authStatus === messaging.AuthorizationStatus.PROVISIONAL;

      if (!enabled) {
        // console.log removed for production
        return false;
      }

      // الحصول على FCM Token
      this.fcmToken = await messaging().getToken();
      // console.log removed for production
      // حفظ التوكن محلياً
      await TempStorageService.setItem('fcmToken', this.fcmToken);

      // إعداد معالجات الإشعارات
      this.setupMessageHandlers();

      this.isInitialized = true;
      return true;
    } catch (error) {
      console.error('خطأ في تهيئة خدمة الإشعارات:', error);
      return false;
    }
  }

  /**
   * إعداد معالجات الإشعارات
   */
  setupMessageHandlers() {
    if (!messaging) {
      return;
    }
    // معالج الإشعارات عند فتح التطبيق
    messaging().onMessage(async remoteMessage => {
      // console.log removed for production
      // عرض الإشعار كـ Alert
      if (remoteMessage.notification) {
        Alert.alert(
          remoteMessage.notification.title || 'إشعار جديد',
          remoteMessage.notification.body || '',
          [
            { text: 'موافق', style: 'default' },
          ]
        );
      }

      // حفظ الإشعار في قاعدة البيانات المحلية
      await this.saveNotificationLocally(remoteMessage);
    });

    // معالج الإشعارات عند النقر عليها (التطبيق مغلق)
    messaging().onNotificationOpenedApp(remoteMessage => {
      // console.log removed for production
      this.handleNotificationAction(remoteMessage);
    });

    // معالج الإشعارات عند فتح التطبيق لأول مرة من إشعار
    messaging()
      .getInitialNotification()
      .then(remoteMessage => {
        if (remoteMessage) {
          // console.log removed for production
          this.handleNotificationAction(remoteMessage);
        }
      });

    // معالج تحديث التوكن
    messaging().onTokenRefresh(token => {
      // console.log removed for production
      this.fcmToken = token;
      TempStorageService.setItem('fcmToken', token);
      // يمكن إرسال التوكن الجديد للخادم هنا
    });
  }

  /**
   * ✅ معالجة إجراءات الإشعارات مع Deep Linking
   */
  handleNotificationAction(remoteMessage) {
    if (!remoteMessage?.data) {
      // console.log removed for production
      return;
    }

    const { type, action, tradeId, userId, screen } = remoteMessage.data;
    // console.log removed for production
    // إذا لم يكن التنقل جاهزاً، احفظ الإشعار للتنفيذ لاحقاً
    if (!navigationRef?.isReady?.()) {
      // console.log removed for production
      this.pendingNotification = remoteMessage;
      return;
    }

    // تحديد الشاشة المستهدفة
    let targetScreen = screen || 'Dashboard';
    let params = {};

    switch (type) {
      case 'trade_signal':
      case 'trade_opened':
        targetScreen = 'Dashboard';
        params = { highlightTrades: true };
        // console.log removed for production
        break;

      case 'trade_completed':
      case 'trade_closed':
      case 'trade_closed_profit':
      case 'trade_closed_loss':
        targetScreen = 'TradeHistory';
        params = { tradeId };
        // console.log removed for production
        break;

      case 'portfolio_update':
      case 'balance_update':
        targetScreen = 'Portfolio';
        // console.log removed for production
        break;

      case 'daily_loss_limit':
      case 'balance_low':
      case 'system_alert':
      case 'alert':
        targetScreen = 'Notifications';
        // console.log removed for production
        break;

      case 'settings':
        targetScreen = 'Settings';
        // console.log removed for production
        break;

      default:
        // console.log removed for production
        targetScreen = 'Dashboard';
    }

    // تنفيذ التنقل
    try {
      navigationRef.navigate(targetScreen, params);
      // console.log removed for production
    } catch (navError) {
      console.error('❌ خطأ في التنقل:', navError);
      // محاولة التنقل للشاشة الرئيسية كخطة بديلة
      try {
        navigationRef.navigate('Dashboard');
      } catch (e) {
        console.error('❌ فشل التنقل البديل:', e);
      }
    }
  }

  /**
   * حفظ الإشعار محلياً
   */
  async saveNotificationLocally(remoteMessage) {
    try {
      const notification = {
        id: Date.now().toString(),
        title: remoteMessage.notification?.title || '',
        body: remoteMessage.notification?.body || '',
        data: remoteMessage.data || {},
        receivedAt: new Date().toISOString(),
        read: false,
      };

      // جلب الإشعارات المحفوظة
      const savedNotifications = await TempStorageService.getItem('notifications');
      let notifications = [];
      if (savedNotifications) {
        try {
          notifications = JSON.parse(savedNotifications);
        } catch (parseError) {
          console.warn('[CRASH_PREVENTION] فشل تحليل الإشعارات المحفوظة:', parseError);
          notifications = [];
        }
      }

      // إضافة الإشعار الجديد
      notifications.unshift(notification);

      // الاحتفاظ بآخر 50 إشعار فقط
      if (notifications.length > 50) {
        notifications.splice(50);
      }

      // حفظ الإشعارات المحدثة
      await TempStorageService.setItem('notifications', JSON.stringify(notifications));
    } catch (error) {
      console.error('خطأ في حفظ الإشعار محلياً:', error);
    }
  }

  /**
   * الحصول على الإشعارات المحفوظة محلياً
   */
  async getLocalNotifications() {
    try {
      const savedNotifications = await TempStorageService.getItem('notifications');
      return savedNotifications ? JSON.parse(savedNotifications) : [];
    } catch (error) {
      console.error('خطأ في جلب الإشعارات المحلية:', error);
      return [];
    }
  }

  /**
   * تحديد إشعار كمقروء
   */
  async markNotificationAsRead(notificationId) {
    try {
      const savedNotifications = await TempStorageService.getItem('notifications');
      let notifications = [];
      if (savedNotifications) {
        try {
          notifications = JSON.parse(savedNotifications);
        } catch (parseError) {
          console.warn('[CRASH_PREVENTION] فشل تحليل الإشعارات في markAsRead:', parseError);
          return false;
        }
      }

      const updatedNotifications = notifications.map(notification =>
        notification.id === notificationId
          ? { ...notification, read: true }
          : notification
      );

      await TempStorageService.setItem('notifications', JSON.stringify(updatedNotifications));
      return true;
    } catch (error) {
      console.error('خطأ في تحديد الإشعار كمقروء:', error);
      return false;
    }
  }

  /**
   * مسح جميع الإشعارات
   */
  async clearAllNotifications() {
    try {
      await TempStorageService.removeItem('notifications');
      return true;
    } catch (error) {
      console.error('خطأ في مسح الإشعارات:', error);
      return false;
    }
  }

  /**
   * الحصول على FCM Token
   */
  async getFCMToken() {
    if (!messaging) {
      console.warn('⚠️ NotificationService: لا يمكن الحصول على FCM Token بدون Firebase messaging');
      return null;
    }
    if (this.fcmToken) {
      return this.fcmToken;
    }

    try {
      const token = await TempStorageService.getItem('fcmToken');
      if (token) {
        this.fcmToken = token;
        return token;
      }

      // إذا لم يكن محفوظ، احصل على واحد جديد
      const newToken = await messaging().getToken();
      this.fcmToken = newToken;
      await TempStorageService.setItem('fcmToken', newToken);
      return newToken;
    } catch (error) {
      console.error('خطأ في الحصول على FCM Token:', error);
      return null;
    }
  }

  /**
   * تسجيل التوكن مع الخادم
   */
  async registerTokenWithServer(userId, databaseApiService) {
    try {
      const token = await this.getFCMToken();
      if (!token) {
        console.error('لا يوجد FCM Token للتسجيل');
        return false;
      }

      // إرسال التوكن للخادم (لا نحتاج userId لأن الـ token يحدد المستخدم)
      const response = await databaseApiService.registerFCMToken(token);
      return response?.success || false;
    } catch (error) {
      console.error('خطأ في تسجيل التوكن مع الخادم:', error);
      return false;
    }
  }

  /**
   * إلغاء تسجيل التوكن من الخادم
   */
  async unregisterTokenFromServer(userId, databaseApiService) {
    try {
      const token = await this.getFCMToken();
      if (!token) {
        return true; // لا يوجد توكن للإلغاء
      }

      // إلغاء التسجيل من الخادم
      const response = await databaseApiService.unregisterFCMToken(userId, token);
      return response.success;
    } catch (error) {
      console.error('خطأ في إلغاء تسجيل التوكن:', error);
      return false;
    }
  }

  /**
   * فحص حالة الإذن للإشعارات
   */
  async checkPermissionStatus() {
    try {
      if (!messaging) {
        return false;
      }
      const authStatus = await messaging().hasPermission();
      return authStatus === messaging.AuthorizationStatus.AUTHORIZED ||
        authStatus === messaging.AuthorizationStatus.PROVISIONAL;
    } catch (error) {
      console.error('خطأ في فحص إذن الإشعارات:', error);
      return false;
    }
  }

  /**
   * طلب الإذن للإشعارات مرة أخرى
   */
  async requestPermission() {
    try {
      if (!messaging) {
        return false;
      }
      const authStatus = await messaging().requestPermission();
      return authStatus === messaging.AuthorizationStatus.AUTHORIZED ||
        authStatus === messaging.AuthorizationStatus.PROVISIONAL;
    } catch (error) {
      console.error('خطأ في طلب إذن الإشعارات:', error);
      return false;
    }
  }
}

