/**
 * Admin API Service - خدمات إدارة النظام
 * ✅ تم إصلاح ازدواج الدوال وتوحيد المسارات
 * ✅ تمييز واضح بين الأدمن والمستخدم
 */

import axios from 'axios';
import { AlertService } from '../components/CustomAlert';
import ToastService from './ToastService';

class AdminApiService {
    constructor() {
        this.client = axios.create({
            baseURL: 'http://localhost:5000',
            timeout: 10000,
            headers: {
                'Content-Type': 'application/json',
            },
        });

        // إضافة interceptor للمصادقة
        this.client.interceptors.request.use(
            (config) => {
                const token = global.authToken;
                if (token) {
                    config.headers.Authorization = `Bearer ${token}`;
                }
                return config;
            },
            (error) => {
                return Promise.reject(error);
            }
        );

        // إضافة interceptor للاستجابة
        this.client.interceptors.response.use(
            (response) => response,
            (error) => {
                if (error.response?.status === 401) {
                    ToastService.showError('انتهت صلاحية الجلسة');
                    // إعادة توجيه لصفحة تسجيل الدخول
                }
                return Promise.reject(error);
            }
        );
    }

    // ✅ دالة موحدة للأخطاء العامة (إصلاح ازدواج)
    async getErrors(filters = {}) {
        try {
            const response = await this.client.get('/api/admin/errors', {
                params: filters,
            });
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Errors');
        }
    }

    // ✅ دالة منفصلة للأخطاء الحرجة (إعادة تسمية لتجنب ازدواج)
    async getCriticalErrors(params = {}) {
        try {
            const response = await this.client.get('/api/admin/system/critical-errors', {
                params,
            });
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Critical Errors');
        }
    }

    // ✅ مسارات موحدة لـ Group A (إصلاح تضارب المسارات)
    async startGroupA() {
        try {
            const response = await this.client.post('/api/admin/group-a/start');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Start Group A');
        }
    }

    async stopGroupA() {
        try {
            const response = await this.client.post('/api/admin/group-a/stop');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Stop Group A');
        }
    }

    async getGroupAStatus() {
        try {
            const response = await this.client.get('/api/admin/group-a/status');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Get Group A Status');
        }
    }

    // ✅ Group B APIs
    async startGroupB() {
        try {
            const response = await this.client.post('/api/admin/group-b/start');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Start Group B');
        }
    }

    async stopGroupB() {
        try {
            const response = await this.client.post('/api/admin/group-b/stop');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Stop Group B');
        }
    }

    async getGroupBStatus() {
        try {
            const response = await this.client.get('/api/admin/group-b/status');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Get Group B Status');
        }
    }

    // ✅ إحصائيات النظام
    async getSystemStats() {
        try {
            const response = await this.client.get('/api/admin/system/stats');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'System Stats');
        }
    }

    // ✅ إحصائيات المستخدمين
    async getUsersStats() {
        try {
            const response = await this.client.get('/api/admin/users/stats');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Users Stats');
        }
    }

    // ✅ إحصائيات التداول
    async getTradingStats() {
        try {
            const response = await this.client.get('/api/admin/trading/stats');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Trading Stats');
        }
    }

    // ✅ إحصائيات المحفظة
    async getPortfolioStats() {
        try {
            const response = await this.client.get('/api/admin/portfolio/stats');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Portfolio Stats');
        }
    }

    // ✅ إدارة إعدادات النظام
    async updateSystemSettings(settings) {
        try {
            const response = await this.client.put('/api/admin/system/settings', settings);
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Update System Settings');
        }
    }

    async getSystemSettings() {
        try {
            const response = await this.client.get('/api/admin/system/settings');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Get System Settings');
        }
    }

    // ✅ إدارة الإشعارات
    async getNotificationSettings() {
        try {
            const response = await this.client.get('/api/admin/notifications/settings');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Notification Settings');
        }
    }

    async updateNotificationSettings(settings) {
        try {
            const response = await this.client.put('/api/admin/notifications/settings', settings);
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Update Notification Settings');
        }
    }

    // ✅ إدارة النظام
    async restartSystem() {
        try {
            const response = await this.client.post('/api/admin/system/restart');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Restart System');
        }
    }

    async stopSystem() {
        try {
            const response = await this.client.post('/api/admin/system/stop');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'Stop System');
        }
    }

    async getSystemStatus() {
        try {
            const response = await this.client.get('/api/admin/system/status');
            return this.handleResponse(response);
        } catch (error) {
            return this.handleError(error, 'System Status');
        }
    }

    // ✅ معالجة الاستجابة
    handleResponse(response) {
        if (response.status === 200 || response.status === 201) {
            return {
                success: true,
                data: response.data,
                status: response.status,
            };
        } else {
            return {
                success: false,
                error: response.data?.message || 'خطأ غير محدد',
                status: response.status,
            };
        }
    }

    // ✅ معالجة الأخطاء
    handleError(error, operation = 'Unknown') {
        console.error(`[AdminApiService] خطأ في ${operation}:`, error);

        let errorMessage = 'حدث خطأ غير متوقع';
        let errorCode = 500;

        if (error.response) {
            // خطأ من الخادم
            errorMessage = error.response.data?.message || error.response.data?.error || 'خطأ في الخادم';
            errorCode = error.response.status;
        } else if (error.request) {
            // خطأ في الشبكة
            errorMessage = 'خطأ في الاتصال بالخادم';
            errorCode = 0;
        } else {
            // خطأ في الإعداد
            errorMessage = error.message || 'خطأ في الإعداد';
            errorCode = 400;
        }

        return {
            success: false,
            error: errorMessage,
            errorCode: errorCode,
            operation: operation,
        };
    }
}

// ✅ إنشاء instance موحد
const adminApiService = new AdminApiService();
export default adminApiService;

/**
 * 🛡️ Console Monitor - مراقب أخطاء Console
 * يلتقط ويراقب جميع أخطاء JavaScript و React
 */

class ConsoleMonitor {
    static init() {
        if (__DEV__) {
            console.log('🔍 Console Monitor initialized');

            // مراقبة أخطاء JavaScript
            const originalError = console.error;
            console.error = (...args) => {
                originalError.apply(console, args);

                const errorMessage = args.join(' ');
                if (this.isReactError(errorMessage)) {
                    this.logReactError(errorMessage);
                }
            };

            // مراقبة تحذيرات React
            const originalWarn = console.warn;
            console.warn = (...args) => {
                originalWarn.apply(console, args);

                const warningMessage = args.join(' ');
                if (this.isReactWarning(warningMessage)) {
                    this.logReactWarning(warningMessage);
                }
            };

            // مراقبة أخطاء الشبكة
            const originalLog = console.log;
            console.log = (...args) => {
                const logMessage = args.join(' ');
                if (this.isNetworkError(logMessage)) {
                    this.logNetworkError(logMessage);
                }
                originalLog.apply(console, args);
            };
        }
    }

    static isReactError(message) {
        return message.includes('Warning:') ||
            message.includes('Error:') ||
            message.includes('undefined is not an object') ||
            message.includes('Cannot read property') ||
            message.includes('TypeError') ||
            message.includes('ReferenceError');
    }

    static isReactWarning(message) {
        return message.includes('Warning:') ||
            message.includes('Each child should have a unique "key" prop') ||
            message.includes('Can not perform a React state update') ||
            message.includes('React state update during render');
    }

    static isNetworkError(message) {
        return message.includes('Network Error') ||
            message.includes('fetch failed') ||
            message.includes('Request failed') ||
            message.includes('Timeout');
    }

    static logReactError(error) {
        console.group('🚨 React Error Detected');
        console.log('Error:', error);
        console.log('Time:', new Date().toLocaleTimeString('ar-SA'));
        console.log('Platform:', Platform.OS);
        console.log('Screen:', this.getCurrentScreen());
        console.groupEnd();
    }

    static logReactWarning(warning) {
        console.group('⚠️ React Warning Detected');
        console.log('Warning:', warning);
        console.log('Time:', new Date().toLocaleTimeString('ar-SA'));
        console.log('Platform:', Platform.OS);
        console.log('Screen:', this.getCurrentScreen());
        console.groupEnd();
    }

    static logNetworkError(error) {
        console.group('🌐 Network Error Detected');
        console.log('Error:', error);
        console.log('Time:', new Date().toLocaleTimeString('ar-SA'));
        console.log('Platform:', Platform.OS);
        console.groupEnd();
    }

    static getCurrentScreen() {
        try {
            // محاولة تحديد الشاشة الحالية من navigation state
            return global.currentScreen || 'Unknown Screen';
        } catch {
            return 'Unknown Screen';
        }
    }

    // دالة لفحص الأخطاء في مكون معين
    static inspectComponent(componentName, props, state) {
        console.group(`🔍 Inspecting ${componentName}`);

        console.log('Props:', props);
        console.log('State:', state);

        // فحص Props غير المعرّفة
        Object.keys(props || {}).forEach(key => {
            if (props[key] === undefined) {
                console.warn(`⚠️ Undefined prop: ${key} in ${componentName}`);
            }
        });

        // فحص State الفاسد
        Object.keys(state || {}).forEach(key => {
            if (state[key] === null || state[key] === undefined) {
                console.warn(`⚠️ Invalid state: ${key} = ${state[key]} in ${componentName}`);
            }
        });

        console.groupEnd();
    }

    // دالة لمراقبة API calls
    static monitorAPI(apiName, startTime) {
        const endTime = performance.now();
        const duration = endTime - startTime;

        if (duration > 2000) { // أكثر من ثانيتين
            console.warn(`🐌 Slow API call detected: ${apiName} took ${duration.toFixed(2)}ms`);
        } else {
            console.log(`✅ API call successful: ${apiName} took ${duration.toFixed(2)}ms`);
        }
    }
}

export default ConsoleMonitor;

/**
 * خدمة الاستجابة اللمسية (Haptic Feedback)
 * ✅ اهتزاز خفيف عند التفاعل
 * ✅ أنواع مختلفة للأحداث المختلفة
 * ✅ يعمل بصمت إذا لم يكن مدعوماً
 */

import { Platform, Vibration } from 'react-native';

// محاولة استيراد react-native-haptic-feedback إذا كان متاحاً
let ReactNativeHapticFeedback = null;
try {
    ReactNativeHapticFeedback = require('react-native-haptic-feedback').default;
} catch (e) {
    // المكتبة غير مثبتة - سنستخدم Vibration كبديل
}

/**
 * أنواع الاستجابة اللمسية
 */
export const HapticTypes = {
    // خفيف - للضغط على الأزرار العادية
    LIGHT: 'impactLight',
    // متوسط - للسحب والإفلات
    MEDIUM: 'impactMedium',
    // قوي - للتأكيدات المهمة
    HEAVY: 'impactHeavy',
    // نجاح - عند إتمام عملية بنجاح
    SUCCESS: 'notificationSuccess',
    // تحذير - عند وجود تحذير
    WARNING: 'notificationWarning',
    // خطأ - عند حدوث خطأ
    ERROR: 'notificationError',
    // اختيار - عند تبديل Switch أو اختيار عنصر
    SELECTION: 'selection',
};

/**
 * خيارات الاهتزاز
 */
const hapticOptions = {
    enableVibrateFallback: true,
    ignoreAndroidSystemSettings: false,
};

/**
 * تشغيل الاستجابة اللمسية
 */
export const triggerHaptic = (type = HapticTypes.LIGHT) => {
    try {
        if (ReactNativeHapticFeedback) {
            // استخدام المكتبة المتقدمة
            ReactNativeHapticFeedback.trigger(type, hapticOptions);
        } else {
            // استخدام Vibration كبديل
            const duration = getVibrationDuration(type);
            if (duration > 0) {
                Vibration.vibrate(duration);
            }
        }
    } catch (error) {
        // صامت - لا نريد أن يفشل التطبيق بسبب الاهتزاز
        console.debug('[Haptic] غير متاح:', error.message);
    }
};

/**
 * تحديد مدة الاهتزاز للبديل
 */
const getVibrationDuration = (type) => {
    switch (type) {
        case HapticTypes.LIGHT:
        case HapticTypes.SELECTION:
            return 10;
        case HapticTypes.MEDIUM:
            return 20;
        case HapticTypes.HEAVY:
            return 30;
        case HapticTypes.SUCCESS:
            return 15;
        case HapticTypes.WARNING:
            return 25;
        case HapticTypes.ERROR:
            return 40;
        default:
            return 10;
    }
};

/**
 * اهتزاز خفيف للضغط على الأزرار
 */
export const hapticLight = () => triggerHaptic(HapticTypes.LIGHT);

/**
 * اهتزاز متوسط
 */
export const hapticMedium = () => triggerHaptic(HapticTypes.MEDIUM);

/**
 * اهتزاز قوي
 */
export const hapticHeavy = () => triggerHaptic(HapticTypes.HEAVY);

/**
 * اهتزاز نجاح
 */
export const hapticSuccess = () => triggerHaptic(HapticTypes.SUCCESS);

/**
 * اهتزاز تحذير
 */
export const hapticWarning = () => triggerHaptic(HapticTypes.WARNING);

/**
 * اهتزاز خطأ
 */
export const hapticError = () => triggerHaptic(HapticTypes.ERROR);

/**
 * اهتزاز اختيار (للـ Switch و Picker)
 */
export const hapticSelection = () => triggerHaptic(HapticTypes.SELECTION);

/**
 * تعطيل/تفعيل الاهتزاز (للإعدادات)
 */
let isHapticEnabled = true;

export const setHapticEnabled = (enabled) => {
    isHapticEnabled = enabled;
};

export const isHapticAvailable = () => {
    return ReactNativeHapticFeedback !== null || Platform.OS !== 'web';
};

/**
 * دالة مساعدة لإضافة الاهتزاز لأي onPress
 */
export const withHaptic = (onPress, hapticType = HapticTypes.LIGHT) => {
    return () => {
        triggerHaptic(hapticType);
        onPress && onPress();
    };
};

/**
 * دالة مساعدة لإضافة الاهتزاز مع تمرير المعاملات
 */
export const withHapticArgs = (onPress, hapticType = HapticTypes.LIGHT) => {
    return (...args) => {
        triggerHaptic(hapticType);
        onPress && onPress(...args);
    };
};

export default {
    triggerHaptic,
    hapticLight,
    hapticMedium,
    hapticHeavy,
    hapticSuccess,
    hapticWarning,
    hapticError,
    hapticSelection,
    setHapticEnabled,
    isHapticAvailable,
    HapticTypes,
    withHaptic,
    withHapticArgs,
};
